ent (金銭)"},{"name":"BRANCH_NAME","label":"Branch Name","group":"Financial & Payment (金銭)"},{"name":"SWIFT_BIC","label":"SWIFT/BIC","group":"Financial & Payment (金銭)"},{"name":"IBAN","label":"IBAN","group":"Financial & Payment (金銭)"},{"name":"INTERMEDIARY_BANK","label":"Intermediary Bank","group":"Financial & Payment (金銭)"},{"name":"ACCOUNT_TYPE","label":"Account Type","group":"Financial & Payment (金銭)"},{"name":"ACCOUNT_NUMBER","label":"Account Number","group":"Financial & Payment (金銭)"},{"name":"ACCOUNT_HOLDER","label":"Account Holder","group":"Financial & Payment (金銭)"},{"name":"ACCOUNT_HOLDER_LOCAL","label":"Account Holder (Local Script)","group":"Financial & Payment (金銭)"},{"name":"TAX_REGISTRATION_NO","label":"Tax Reg No.","group":"Financial & Payment (金銭)"},{"name":"TRANSFER_FEE_CODE","label":"Bank Fee Code (OUR/SHA/BEN)","group":"Financial & Payment (金銭)"},{"name":"ITEM_NAME","label":"Item Name (Single)","group":"Services & Deliverables"},{"name":"PAYMENT_METHOD","label":"Payment Method (Single)","group":"Services & Deliverables"},{"name":"ACCEPT_METHOD","label":"Acceptance Method","group":"Acceptance & Signature","type":"textarea"},{"name":"ACCEPT_REPLY_DUE_DATE","label":"Acceptance Deadline","group":"Acceptance & Signature","type":"date"},{"name":"SHOW_SIGN_SECTION","label":"Show Signature Box","group":"Acceptance & Signature","type":"boolean"},{"name":"CONTRACTOR_ACCEPT_DATE","label":"Acceptance Date (Manual)","group":"Acceptance & Signature","type":"date"},{"name":"TERMS_VERSION_DATE","label":"Terms Version Date","group":"Legal Clauses"},{"name":"NDA_SURVIVAL_YEARS","label":"Confidentiality Survival (Years)","group":"Legal Clauses","type":"number"},{"name":"LATE_PAYMENT_RATE","label":"Late Payment Interest Rate","group":"Legal Clauses"}]$json$::jsonb, 'initial import (Phase 1 / A2)', 'seed-templates'
