SELECT t.id, 1, $tpl$<!DOCTYPE html>
<html lang="ja">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>業務委託基本契約書</title>
    <style>
        @page {
            size: A4;
            margin: 18mm 20mm 22mm 25mm;
            @bottom-center {
                content: "- " counter(page) " -";
                font-size: 8.5pt;
                font-family: "Noto Serif CJK JP", "IPAMincho", serif;
            }
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body {
            font-family: "Noto Serif CJK JP", "IPAMincho", "MS Mincho", serif;
            font-size: 10pt;
            line-height: 1.75;
            color: #000;
            background-color: #fff;
            margin: 0;
            padding: 0;
        }

        .contract-document {
            max-width: 210mm;
            margin: 0 auto;
            background-color: #fff;
            padding: 18mm 20mm 22mm 25mm;
            box-sizing: border-box;
        }

        /* ===== ドキュメントヘッダー ===== */
        .doc-header {
            display: flex;
            justify-content: flex-end;
            align-items: baseline;
            gap: 0.45em;
            margin-bottom: 0.5em;
            font-size: 8.5pt;
            color: #555;
            letter-spacing: 0.05em;
        }

        .doc-header .header-separator {
            color: #aaa;
        }

        /* ===== タイトル ===== */
        h1.contract-title {
            text-align: center;
            font-size: 14pt;
            font-weight: bold;
            letter-spacing: 0.35em;
            margin-bottom: 0.9em;
            text-decoration: underline;
            text-underline-offset: 0.22em;
        }

        h2 {
            font-size: 11pt;
            margin-top: 14px;
            margin-bottom: 6px;
            border-bottom: 1px solid #999;
            padding-bottom: 2px;
        }

        p {
            margin-bottom: 6px;
            text-align: justify;
        }

        ul, ol {
            padding-left: 18px;
            margin-bottom: 6px;
        }

        li { margin-bottom: 3px; }

        /* ===== 頭書き表 ===== */
        .tobogaki {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 1.15em;
            font-size: 9pt;
            line-height: 1.6;
            border-top: 1.5pt solid #1a1a1a;
            border-bottom: 1.5pt solid #1a1a1a;
        }

        .tobogaki th,
        .tobogaki td {
            border: none;
            border-bottom: 0.5pt solid #d8d8d8;
            padding: 0.45em 0.7em;
            vertical-align: top;
        }

        .tobogaki .sec-row td {
            padding-top: 0.9em;
            padding-bottom: 0.25em;
            border-bottom: 0.5pt solid #888;
            font-size: 7.5pt;
            font-weight: bold;
            letter-spacing: 0.25em;
            color: #555;
            text-transform: uppercase;
        }

        .tobogaki .col-item {
            width: 36%;
            font-weight: bold;
            color: #1a1a1a;
            padding-left: 0.5em;
        }

        .tobogaki .col-item .art-ref {
            font-size: 7.5pt;
            font-weight: normal;
            color: #777;
        }

        .tobogaki .col-item .sub-note {
            display: block;
            font-size: 7.5pt;
            font-weight: normal;
            color: #888;
            margin-top: 0.1em;
        }

        .tobogaki .col-value {
            width: 64%;
            word-break: break-all;
            overflow-wrap: break-word;
            color: #1a1a1a;
        }

        .tobogaki .special-cell {
            min-height: 2.5em;
            word-break: break-all;
            overflow-wrap: break-word;
            color: #1a1a1a;
            white-space: pre-wrap;
        }

        /* ===== 頭書き下部署名欄 ===== */
        .head-signature {
            margin: 0.2em 0 1.3em;
            page-break-inside: avoid;
            font-size: 9.2pt;
            line-height: 1.55;
        }

        .head-signature .sig-date {
            text-align: right;
            margin-bottom: 0.8em;
        }

        .head-signature .sig-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 1.2em;
        }

        .head-signature .sig-party {
            border-top: 1pt solid #1a1a1a;
            padding-top: 0.5em;
        }

        .head-signature .party-label {
            font-weight: bold;
            margin-bottom: 0.3em;
        }

        .head-signature .sig-name-row {
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 0.8em;
            margin-top: 0.3em;
        }

        .head-signature .stamp-box {
            width: 52px;
            height: 52px;
            border: 1pt solid #1a1a1a;
            display: flex;
            justify-content: center;
            align-items: center;
            font-size: 11pt;
            background-color: #fff;
            flex-shrink: 0;
        }

        .preamble {
            font-size: 9.5pt;
            text-indent: 1em;
            margin-bottom: 0.9em;
            line-height: 1.7;
        }

        .article-block > ol {
            list-style-type: none;
            counter-reset: item;
            padding-left: 0;
        }

        .article-block > ol > li {
            position: relative;
            padding-left: 1.5em;
            margin-bottom: 5px;
        }

        .article-block > ol > li::before {
            counter-increment: item;
            content: counter(item);
            position: absolute;
            left: 0.2em;
            top: 0;
            font-weight: normal;
        }

        .article-block > ol > li > ol {
            list-style-type: none;
            counter-reset: sub-item;
            padding-left: 0;
            margin-top: 5px;
        }

        .article-block > ol > li > ol > li {
            position: relative;
            padding-left: 2.5em;
            margin-bottom: 5px;
        }

        .article-block > ol > li > ol > li::before {
            counter-increment: sub-item;
            content: "(" counter(sub-item) ")";
            position: absolute;
            left: 0;
            top: 0;
        }

        .article-block { page-break-inside: auto; }
        .article-block h2 { page-break-after: avoid; }
        .no-break { page-break-inside: avoid; }

        @media print {
            body { background-color: #fff; padding: 0; }
            .contract-document {
                box-shadow: none;
                margin: 0;
                width: 100%;
                max-width: none;
                padding: 0;
            }
            h2 { page-break-after: avoid; margin-top: 10px; }
            .article-block { page-break-inside: auto; }
            .article-block > ol > li { page-break-inside: auto; }
            .head-signature, .tobogaki { page-break-inside: avoid; }
            p { orphans: 3; widows: 3; }
        }
    </style>
</head>
<body>

<div class="contract-document">

    <div class="doc-header">
        <span class="header-item">契約締結日：{{CONTRACT_DATE}}</span>
        <span class="header-separator">｜</span>
        <span class="header-item contract-no">契約番号：{{CONTRACT_NO}}</span>
    </div>

    <h1 class="contract-title">業務委託基本契約書</h1>

    <!-- ======================================================
         頭書き（当事者目録・契約条件一覧）
         ====================================================== -->
    <table class="tobogaki">
        <tbody>
            <!-- 当事者 -->
            <tr class="sec-row"><td colspan="2">当　事　者</td></tr>
            <tr>
                <td class="col-item">甲（委託者）</td>
                <td class="col-value">
                    {{PARTY_A_ADDRESS}}<br>
                    {{PARTY_A_NAME}}<br>
                    {{PARTY_A_REP}}
                </td>
            </tr>
            <tr>
                <td class="col-item">乙（受託者）</td>
                <td class="col-value">
                    {{VENDOR_ADDRESS}}<br>
                    {{VENDOR_NAME}}<br>
                    {{VENDOR_REP}}
                </td>
            </tr>

            <!-- 基本条件 -->
            <tr class="sec-row"><td colspan="2">基　本　条　件</td></tr>
