      display: flex;
      justify-content: space-between;
      align-items: flex-end;
    }
    .doc-title { font-size: 20pt; font-weight: bold; letter-spacing: 0.08em; }
    .doc-meta { text-align: right; font-size: 9pt; line-height: 1.9; }

    /* 分納バッジ — 分割時のみ表示 (納品完了バッジは廃止 Phase 9c) */
    .delivery-badge {
      display: inline-block;
      border: 1.5px dashed #000;
      padding: 2px 10px;
      font-size: 9pt;
      font-weight: bold;
      margin-left: 10px;
      vertical-align: middle;
      color: #555;
    }
    /* Phase 23.1: 再発行版バッジ — 外部要請による修正版 (revision >= 1) で表示 */
    .reissue-badge {
      display: inline-block;
      border: 1.5px solid #b91c1c;
      background: #fef2f2;
      color: #b91c1c;
      padding: 2px 10px;
      font-size: 9pt;
      font-weight: bold;
      margin-left: 10px;
      vertical-align: middle;
      letter-spacing: 0.05em;
    }

    .parties { display: flex; justify-content: space-between; margin-bottom: 14px; gap: 16px; }
    .party-block { flex: 1; }
    .party-label { font-size: 8pt; color: #555; margin-bottom: 2px; }
    .party-name { font-size: 13pt; font-weight: bold; border-bottom: 1px solid #000; padding-bottom: 2px; }
    .party-rep {
      font-size: 10pt;
      margin-top: 6px;
      padding-top: 5px;
      border-top: 1px dashed #ccc;
    }

    /* ② 相手方登録番号表示 */
    .party-reg-no {
      font-size: 8.5pt;
      margin-top: 5px;
      color: #333;
      letter-spacing: 0.01em;
    }
    .party-reg-no strong {
      font-family: "Courier New", "Lucida Console", monospace;
      font-size: 9pt;
      letter-spacing: 0.04em;
    }

    .section-title {
      font-size: 9pt;
      font-weight: bold;
      border-left: 3px solid #000;
      padding-left: 6px;
      margin: 12px 0 6px;
      letter-spacing: 0.05em;
    }

    table { width: 100%; border-collapse: collapse; font-size: 9.5pt; }
    th { background: #f0f0f0; border: 1px solid #999; padding: 5px 8px; font-weight: bold; text-align: center; }
    td { border: 1px solid #ccc; padding: 5px 8px; }
    td.right { text-align: right; }
    td.center { text-align: center; }
    td.label { background: #f7f7f7; font-weight: bold; width: 140px; }

    tr.total-row td { background: #f0f0f0; font-weight: bold; font-size: 11pt; }
    tr.subtotal-row td { background: #f8f8f8; }

    /* Phase 23.4: 成果物セル内の item_name / spec 併記レイアウト。
       旧「仕様」列を廃止し、成果物セル内に補足として表示する。
       背景は付けず (テーブル背景のまま) 左の縦線だけで補足を表現。 */
    .item-name {
      font-weight: bold;
      line-height: 1.5;
    }
    .item-spec {
      margin-top: 3px;
      padding-left: 8px;
      border-left: 2px solid #666;
      font-size: 9pt;
      color: #000;
      line-height: 1.55;
      white-space: pre-line;     /* spec 内の \n を改行として保持 */
    }

    /* ④ 軽減税率対象識別マーク（消費税法57条の4第1項第3号ロ） */
    .reduced-mark {
      display: inline-block;
      border: 1px solid #666;
      font-size: 7pt;
      line-height: 1;
      padding: 1px 3px;
      margin-right: 4px;
      vertical-align: middle;
      color: #444;
    }
    .reduced-note {
      font-size: 8pt;
      color: #555;
      margin-top: 5px;
      padding-left: 2px;
    }

    /* 変更履歴ブロック */
    .change-log-section {
      border: 1px solid #bbb;
      padding: 8px 10px;
      margin: 12px 0;
      font-size: 8.5pt;
    }
    .change-log-title {
      font-weight: bold;
      font-size: 9pt;
      margin-bottom: 6px;
      padding-bottom: 4px;
      border-bottom: 1px solid #ddd;
    }
    .change-log-row {
      display: flex;
      gap: 10px;
      padding: 3px 0;
      border-bottom: 1px dashed #e0e0e0;
      line-height: 1.5;
    }
    .change-log-row:last-child { border-bottom: none; }
    .change-date { color: #555; min-width: 80px; }
    .change-field { font-weight: bold; min-width: 60px; }
    .change-before { color: #888; text-decoration: line-through; }
    .change-arrow { color: #555; margin: 0 4px; }
    .change-after { font-weight: bold; }
    .change-reason { color: #444; margin-left: 8px; font-style: italic; }

    /* 進捗サマリー */
    .progress-bar-wrap {
      border: 1px solid #ccc;
      padding: 8px 10px;
      margin-bottom: 12px;
    }
    .progress-bar-title { font-size: 8pt; color: #555; margin-bottom: 4px; }
    .progress-bar-track { height: 12px; background: #e8e8e8; border-radius: 2px; overflow: hidden; margin-bottom: 4px; }
    .progress-bar-fill { height: 100%; background: #444; }
    .progress-bar-labels { display: flex; justify-content: space-between; font-size: 7.5pt; color: #555; }

    .confirmation-text {
      border: 1px solid #ccc;
      background: #fafafa;
      padding: 8px 12px;
      margin-bottom: 12px;
      font-size: 9.5pt;
    }

    .conditions { display: flex; gap: 12px; margin-bottom: 12px; }
    .condition-box { flex: 1; border: 1px solid #bbb; padding: 8px 10px; }
    .condition-box h3 { font-size: 8.5pt; font-weight: bold; border-bottom: 1px solid #ddd; margin-bottom: 5px; padding-bottom: 3px; }
    .condition-box .highlight { font-size: 11pt; font-weight: bold; }

    /* みなし同意ブロック */
    .confirm-box {
      border: 1px solid #ccc;
      background: #fafafa;
      padding: 10px 12px;
      margin-top: 14px;
      font-size: 9pt;
      line-height: 1.6;
      break-inside: avoid;
      page-break-inside: avoid;
    }
    .confirm-box p { margin: 0 0 6px 0; }
    .confirm-box p:last-child { margin-bottom: 0; }
    .confirm-box .proviso {
      font-size: 8.3pt;
      color: #555;
      border-top: 1px dashed #ccc;
      padding-top: 6px;
      margin-top: 8px;
    }
    .confirm-box .contact {
      font-size: 8.7pt;
      margin-top: 8px;
      padding-top: 6px;
      border-top: 1px solid #ddd;
    }

  </style>
</head>
<body>

  {{!-- ヘッダー (Phase 9c)
       - 「納品完了」バッジは廃止 (分割時のみバッジ表示)
       - 旧 .doc-number ({{issueKey}}-{{itemNo}}-{{deliveryNo}}) は廃止
         代わりに「発注番号 = 親 PO の document_number」を表示
  --}}
  <div class="doc-header">
    <div>
      <span class="doc-title">検　収　書</span>
      {{#if (or (eq isPartial "分割") (eq isPartial true))}}
      <span class="delivery-badge">分割納品 第{{deliveryNo}}回 / 全{{totalDeliveries}}回予定</span>
      {{/if}}
      {{#if (gt REVISION 0)}}
      <span class="reissue-badge">修正版 Rev. {{REVISION}}</span>
      {{/if}}
    </div>
    <div class="doc-meta">
      <div>発注番号: <strong>{{or parent_po_number issueKey}}</strong></div>
      <div>明細No.: {{itemNo}}{{#if itemCount}} / 全{{itemCount}}件中{{/if}}</div>
      <div>発行日: {{formatDate documentDate}}</div>
    </div>
  </div>

  {{!-- 当事者ブロック (Phase 9c)
       受託者:
         - 個人 → 「<名前> 様」
         - 法人 → 「<会社名> 御中」 + 棒線 + 「<代表者名> 様」
       発注者:
         住所 / 建物 / 部署 / 担当を別行に整理
  --}}
  <div class="parties">
    <div class="party-block">
      <div class="party-label">受託者（課税仕入れの相手方）</div>
      {{!-- 法人 = 「御中」+ 棒線 + 代表者「様」 / 個人 = 「様」のみ
           COUNTERPARTY_IS_CORPORATION は文字列 "法人" / "個人" (Phase 9d: select 化)。
           後方互換: 古い boolean true もそのまま「法人」扱い --}}
      <div class="party-name">
        {{counterparty}}
        {{#if (eq COUNTERPARTY_IS_CORPORATION "法人")}}御中{{else}}{{#if (eq COUNTERPARTY_IS_CORPORATION true)}}御中{{else}}様{{/if}}{{/if}}
      </div>
      {{#if (eq COUNTERPARTY_IS_CORPORATION "法人")}}
        {{#if counterpartyRep}}
        <div class="party-rep">{{counterpartyRep}} 様</div>
        {{/if}}
      {{else}}
        {{#if (eq COUNTERPARTY_IS_CORPORATION true)}}
          {{#if counterpartyRep}}
          <div class="party-rep">{{counterpartyRep}} 様</div>
          {{/if}}
        {{/if}}
      {{/if}}
      {{#if counterpartyTni}}
      <div class="party-reg-no">登録番号: <strong>{{counterpartyTni}}</strong></div>
      {{/if}}
    </div>
    <div class="party-block" style="text-align:right; font-size:8.5pt; line-height:1.9;">
      <div style="font-size:11pt; font-weight:bold;">株式会社アークライト</div>
      <div>〒101-0052 東京都千代田区神田小川町1-2</div>
      <div>風雲堂ビル2階</div>
      <div style="margin-top:4px;">{{inspectorDept}}</div>
      <div>担当: {{inspectorName}}</div>
    </div>
  </div>

  {{!-- 検収確認文 — 日付は YYYY年MM月DD日 (formatDate) --}}
  <div class="confirmation-text">
    　納品日 （役務完了日）<strong>{{formatDate deliveredAt}}</strong> に納品（役務提供完了）された下記成果物（役務内容）について検収を行い、
    検収日 <strong>{{formatDate inspectionCompletedAt}}</strong> に検収完了致しましたのでご通知します。
    {{#if (or (eq isPartial "分割") (eq isPartial true))}}本書は分割納品（第{{deliveryNo}}回）に係る検収書です。{{/if}}
  </div>

  {{!-- 納品進捗サマリー（分割時のみ） --}}
  {{#if (or (eq isPartial "分割") (eq isPartial true))}}
  <div class="progress-bar-wrap">
    <div class="progress-bar-title">本発注全体の納品・検収進捗</div>
    <div class="progress-bar-track">
      <div class="progress-bar-fill" style="width: {{inspectedPct}}%;"></div>
    </div>
    <div class="progress-bar-labels">
      <span>検収済: ¥{{inspectedAmountStr}} / 発注総額: ¥{{totalOrderAmountStr}}</span>
      <span>残: ¥{{pendingAmountStr}}</span>
    </div>
  </div>
  {{/if}}

  {{!-- 今回納品明細
       適格請求書記載要件（消費税法57条の4）に対応する項目：
         納品日（課税仕入れの年月日）、成果物・業務内容（軽減税率対象の旨を含む）、
         支払対価・税率、消費税額
       Phase 9c: description / spec は親 PO 発見時に form-context で自動補完
       Phase 23.0.4: delivery_line_items[] が複数あれば each ループで複数行を描画。
                      空のときは従来の単一行 ({{description}}) を fallback として表示。
  --}}
  <div class="section-title">■ 今回の納品内容</div>
  <table style="margin-bottom:4px;">
    <thead>
      <tr>
        <th style="width:6%">No.</th>
        <th style="width:64%">成果物・業務内容</th>
        <th style="width:15%">納品日</th>
        <th style="width:15%">支払対価（税抜）</th>
      </tr>
    </thead>
    <tbody>
      {{!-- Phase 23.4: 旧「仕様」列を削除し、「成果物・業務内容」セル内に
           item_name (太字) + spec (補足、左に縦線) を併記するレイアウトに。
           spec 空の行は補足ブロック自体を表示しない (= 行高は item_name 1 行)。
           長文 spec の場合に行が縦に間延びする問題を解消。 --}}
      {{#if (gt (length delivery_line_items) 0)}}
        {{#each delivery_line_items}}
          <tr>
            <td class="center">{{index1 @index}}</td>
            <td>
              <div class="item-name">{{#if ../isReducedTax}}<span class="reduced-mark">※</span>{{/if}}{{or item_name ../description}}</div>
              {{#if (or spec ../spec)}}
              <div class="item-spec">{{or spec ../spec}}</div>
              {{/if}}
            </td>
            <td class="center">{{formatDate (or delivery_date ../deliveredAt)}}</td>
            <td class="right">{{formatYen (or inspected_amount_ex_tax amount_ex_tax)}}</td>
          </tr>
        {{/each}}
      {{else}}
        <tr>
          <td class="center">{{itemNo}}</td>
          <td>
            <div class="item-name">{{#if isReducedTax}}<span class="reduced-mark">※</span>{{/if}}{{description}}</div>
            {{#if spec}}
            <div class="item-spec">{{spec}}</div>
            {{/if}}
          </td>
          <td class="center">{{formatDate deliveredAt}}</td>
          <td class="right">¥{{deliveredAmountStr}}</td>
        </tr>
      {{/if}}
      {{#if otherFeesTaxable}}
      {{!-- Phase 23.6.16: その他手数料がある場合、消費税は末尾の「支払額サマリー」で
           検収税抜＋手数料税抜を合算して 1 回だけ計算する (二重計上を避けるため、
           ここでは検収の税抜小計のみ表示)。 --}}
      <tr class="total-row">
        <td colspan="3" class="right">検収 小計（税抜）</td>
        <td class="right">¥{{deliveredAmountStr}}</td>
      </tr>
      {{else}}
      <tr>
        <td colspan="3" class="right">
          消費税({{taxRate}}%{{#if isReducedTax}}・軽減税率対象{{/if}})
        </td>
        <td class="right">¥{{taxAmountStr}}</td>
      </tr>
      <tr class="total-row">
        <td colspan="3" class="right">今回検収金額(税込)</td>
        <td class="right">¥{{totalAmountStr}}</td>
      </tr>
      {{/if}}
    </tbody>
  </table>
  {{#if isReducedTax}}
  <div class="reduced-note">※ 軽減税率（8%）対象品目</div>
  {{/if}}

  {{!-- Phase 17m: 経費精算 (税込み額) — 親 PO の order_expenses から
       「今回含める」とチェックされた行のみを描画。 --}}
  {{#if expenses}}
  <div class="section-title">■ 今回精算する経費（交通費等・税込み額）</div>
  <table style="margin-bottom:4px;">
    <thead>
      <tr>
        <th style="width:6%">No.</th>
        <th style="width:34%">費目</th>
        <th style="width:30%">仕様 / 区間 等</th>
        <th style="width:15%">発生日</th>
        <th style="width:15%">金額（税込）</th>
      </tr>
    </thead>
    <tbody>
      {{#each expenses}}
      <tr>
        <td class="center">{{line_no}}</td>
        <td>{{expense_name}}</td>
        <td>{{spec}}{{#if remarks}}<div style="font-size:8pt;color:#666;margin-top:2px;">{{remarks}}</div>{{/if}}</td>
        <td class="center">{{formatDate spent_date}}</td>
        <td class="right">¥{{formatCurrency amount_inc_tax}}</td>
      </tr>
      {{/each}}
      <tr class="total-row">
        <td colspan="4" class="right">経費合計（税込）</td>
        <td class="right">¥{{expensesTotalIncTaxStr}}</td>
      </tr>
    </tbody>
  </table>
  <div style="font-size:8.5pt;color:#666;margin-top:2px;">※ 経費は税込み額にて精算します（消費税の二重計上はしません）。</div>
  {{/if}}

  {{!-- Phase 22.21.57: その他手数料 (税抜・コーディネート費・振込手数料等) --}}
  {{#if other_fees}}
  {{#if (gt (length other_fees) 0)}}
  <div class="section-title">■ 今回精算するその他手数料（税抜）</div>
  <table style="margin-bottom:4px;">
    <thead>
      <tr>
        <th style="width:6%">No.</th>
        <th style="width:64%">項目名</th>
        <th style="width:15%">金額（税抜）</th>
        <th style="width:15%">摘要</th>
      </tr>
    </thead>
    <tbody>
      {{#each other_fees}}
      <tr>
        <td class="center">{{line_no}}</td>
        <td>{{fee_name}}</td>
        <td class="right">¥{{formatCurrency amount}}</td>
        <td>{{remarks}}</td>
      </tr>
      {{/each}}
      <tr class="total-row">
        <td colspan="2" class="right">手数料合計（税抜）</td>
        <td class="right">¥{{otherFeesTotalStr}}</td>
        <td></td>
      </tr>
    </tbody>
  </table>
  <div style="font-size:8.5pt;color:#666;margin-top:2px;">※ その他手数料は税抜表示。消費税は検収金額と合算し、下記「支払額サマリー」で税率ごとに一括計算します（二重計上はしません）。</div>
  {{/if}}
  {{/if}}

  {{!-- Phase 23.6.16: 支払額サマリー（検収書は仕入明細書として消費税法57条の4 の
       記載要件に対応）。検収書は発注者が発行する書類のため「請求書」とは名乗らない。
       検収金額(税抜) と その他手数料(税抜) を税率ごとに区分して合算し、消費税を
       1 回だけ計算する。経費(税込)は課税対象外の立替として別掲。手数料がある
       ときのみ表示 (手数料が無ければ上の「今回検収金額(税込)」で完結する)。 --}}
  {{#if otherFeesTaxable}}
  <div class="section-title">■ 支払額サマリー</div>
  <table style="margin-bottom:4px;">
    <tbody>
      <tr>
        <td style="width:70%;" class="right">検収金額（税抜）</td>
        <td style="width:30%;" class="right">¥{{deliveredAmountStr}}</td>
      </tr>
      <tr>
        <td class="right">その他手数料（税抜）</td>
        <td class="right">¥{{otherFeesTotalStr}}</td>
      </tr>
      <tr class="total-row">
        <td class="right">{{taxRate}}%対象 税抜合計</td>
        <td class="right">¥{{taxableSubtotalExTaxStr}}</td>
      </tr>
      <tr>
        <td class="right">消費税（{{taxRate}}%）</td>
        <td class="right">¥{{combinedTaxStr}}</td>
      </tr>
      <tr class="total-row" style="background:#f3f3f3;">
        <td class="right">税込合計</td>
        <td class="right">¥{{taxableTotalIncTaxStr}}</td>
      </tr>
      {{#if expenses}}
      <tr>
        <td class="right">経費（税込・課税対象外／別精算）</td>
        <td class="right">¥{{expensesTotalIncTaxStr}}</td>
      </tr>
      {{/if}}
    </tbody>
  </table>
  <div style="font-size:8.5pt;color:#666;margin-top:2px;">
    ※ 消費税は {{taxRate}}%対象（検収金額＋その他手数料）の税抜合計に対し、税率ごとに区分して一括計算しています（消費税の二重計上はしません）。{{#if counterpartyTni}} 登録番号: {{counterpartyTni}}{{/if}}
  </div>
  {{/if}}

  {{!-- 検収金額（税込）+ その他手数料（税込・上のサマリーで合算課税）+ 経費（税込） の総支払額 --}}
  {{#if (or expenses other_fees)}}
  <table style="margin-top:8px;margin-bottom:4px;">
    <tbody>
      <tr class="total-row" style="background:#eef6ff;">
        <td style="width:85%;" class="right"><strong>本検収書に基づく総支払額（税込・経費 / 手数料含む）</strong></td>
        <td style="width:15%;" class="right"><strong>¥{{grandTotalPayableStr}}</strong></td>
      </tr>
    </tbody>
  </table>
  {{/if}}

  {{!-- 変更履歴（あれば） --}}
  {{#if hasChangeLogs}}
  <div class="change-log-section">
    <div class="change-log-title">⚠️ 変更履歴（当初発注条件からの変更）</div>
    {{#each changeLogs}}
    <div class="change-log-row">
      <span class="change-date">{{this.changedAt}}</span>
      <span class="change-field">{{this.fieldLabel}}</span>
      <span class="change-before">{{this.beforeValue}}</span>
      <span class="change-arrow">→</span>
      <span class="change-after">{{this.afterValue}}</span>
      <span class="change-reason">（理由: {{this.reason}}）</span>
    </div>
    {{/each}}
  </div>
  {{/if}}

  {{!-- 支払条件・発注情報 — 期日表記は formatDate で YYYY年MM月DD日 --}}
  <div class="conditions">
    <div class="condition-box">
      <h3>■ 支払条件</h3>
      <p>{{paymentConditionSummary}}</p>
      <p>支払期日: <span class="highlight">{{formatDate paymentDueDate}}</span></p>
    </div>
    <div class="condition-box">
      <h3>■ 振込先</h3>
      <p>{{bankName}} {{branchName}}</p>
      <p>{{accountType}} {{accountNo}}</p>
      <p>口座名義: {{accountHolder}}</p>
    </div>
    <div class="condition-box">
      <h3>■ 発注情報</h3>
      <p>発注日: {{formatDate orderDate}}</p>
      <p>発注番号: <strong>{{or parent_po_number issueKey}}</strong></p>
      <p>明細No.: {{itemNo}}{{#if itemCount}} / 全{{itemCount}}件中{{/if}}</p>
    </div>
  </div>



  {{!-- みなし同意 — 連絡先は DB の staff (inspectorDept / inspectorName / inspectorEmail) から自動補完 --}}
  <div class="section-title">■ 本検収書の内容に関するご確認のお願い</div>
  <div class="confirm-box">
    <p>本検収書にご記載の内容（検収対象成果物、仕様、数量、検収日、金額等）についてご確認のうえ、記載事項に相違または異議がある場合は、本書が貴殿に到達した日の翌日（同日が営業日でない場合は翌営業日）から起算して <strong>5営業日以内</strong> に、下記連絡先宛に書面または電子メールにより、その旨および具体的内容をご通知くださいますようお願いいたします。</p>
    <p>上記期間内に何らのご通知もいただけない場合、本検収書の記載内容（検収日、検収金額、検収対象の範囲を含みます。）について貴殿にご異議がないものとして取り扱わせていただきます。</p>
    <p class="proviso">※ 本取扱いは、製造委託等に係る中小受託事業者に対する代金の支払の遅延等の防止に関する法律（中小受託取引適正化法）、特定受託事業者に係る取引の適正化等に関する法律その他関連法令に基づき貴殿に認められる権利を制限するものではありません。</p>
    <div class="contact">
      <strong>【ご連絡先】</strong><br>
      株式会社アークライト　{{inspectorDept}}　担当: {{inspectorName}}<br>
      E-mail: {{inspectorEmail}}
    </div>
  </div>

</body>
</html>
$tpl$, $json$[{"name":"issueKey","label":"Backlog 課題キー","group":"I. 基本情報","dbField":"backlog.issueKey","helpText":"Backlog 課題から文書を作成した場合に自動補完されます。手動作成時は空欄のままで問題ありません (課題との紐づけは文書作成側で記録されます)。"},{"name":"parent_po_number","label":"発注番号 (親 PO 文書番号)","group":"I. 基本情報","helpText":"親 PO を選択 / 自動発見すると document_number が入る。PDF ヘッダ「発注番号」に表示"},{"name":"documentDate","label":"検収書発行日","group":"I. 基本情報","type":"date","required":true,"dbField":"auto.today","helpText":"未入力だと PDF の発行日が空欄になります"},{"name":"orderDate","label":"発注日","group":"I. 基本情報","type":"date","helpText":"親 PO を選択すると created_at / due_date から自動補完"},{"name":"itemNo","label":"明細番号","group":"I. 基本情報","placeholder":"1"},{"name":"itemCount","label":"総明細数","group":"I. 基本情報","placeholder":"1"},{"name":"deliveryNo","label":"今回の納品回数","group":"I. 基本情報","placeholder":"1"},{"name":"totalDeliveries","label":"総予定回数","group":"I. 基本情報","placeholder":"1"},{"name":"isPartial","label":"分割納品","group":"I. 基本情報","type":"select","options":["分割","完了"],"helpText":"親 PO 選択時に既存検収件数から自動判定。手動でも変更可"},{"name":"counterparty","label":"受託者名","group":"II. 受託者 (取引先)","required":true,"dbField":"vendor.vendor_name","helpText":"[取引先] ボタンで自動入力"},{"name":"COUNTERPARTY_IS_CORPORATION","label":"受託者種別","group":"II. 受託者 (取引先)","type":"select","options":["法人","個人"],"helpText":"法人=「御中」+代表者「様」 / 個人=「様」のみ。[取引先] ボタンで vendor.entity_type から自動判定"},{"name":"counterpartyRep","label":"受託者代表者名","group":"II. 受託者 (取引先)","placeholder":"例: 代表取締役 山田 太郎","helpText":"法人の場合のみ表示。「様」は自動付与"},{"name":"counterpartyTni","label":"インボイス登録番号 (T-)","group":"II. 受託者 (取引先)","dbField":"vendor.invoice_registration_number"},{"name":"inspectorDept","label":"検収者部署","group":"III. 検収者 (自社)","required":true,"dbField":"staff.department","helpText":"[Sync Staff] で自動入力"},{"name":"inspectorName","label":"検収者氏名","group":"III. 検収者 (自社)","required":true,"dbField":"staff.staff_name"},{"name":"inspectorEmail","label":"検収者メールアドレス","group":"III. 検収者 (自社)","dbField":"staff.email","helpText":"みなし同意ブロックの連絡先に出力。[Sync Staff] で自動入力"},{"name":"deliveredAt","label":"実納品日","group":"III. 検収者 (自社)","type":"date","required":true},{"name":"inspectionCompletedAt","label":"検収完了日","group":"III. 検収者 (自社)","type":"date","required":true},{"name":"paymentDueDate","label":"支払期日","group":"III. 検収者 (自社)","type":"date"},{"name":"description","label":"成果物・業務内容","group":"IV. 納品明細","type":"textarea","required":true},{"name":"spec","label":"仕様・内容詳細","group":"IV. 納品明細","type":"textarea"},{"name":"linked_po_number","label":"紐付け発注番号 (PO)","group":"IV. 納品明細","helpText":"[PO紐付] ボタンで External Asset から取得"},{"name":"isReducedTax","label":"軽減税率対象","group":"IV. 納品明細","type":"boolean"},{"name":"deliveredAmountStr","label":"納品額 (税抜)","group":"IV. 納品明細","required":true,"placeholder":"1,000,000"},{"name":"taxRate","label":"税率","group":"IV. 納品明細","type":"select","options":["10","8"],"placeholder":"10"},{"name":"taxAmountStr","label":"消費税額","group":"IV. 納品明細","placeholder":"100,000"},{"name":"totalAmountStr","label":"合計額 (税込)","group":"IV. 納品明細","placeholder":"1,100,000"},{"name":"inspectedPct","label":"検収率 (%)","group":"V. 進捗・財務 (任意)","placeholder":"100"},{"name":"inspectedAmountStr","label":"検収済額","group":"V. 進捗・財務 (任意)"},{"name":"totalOrderAmountStr","label":"発注総額","group":"V. 進捗・財務 (任意)"},{"name":"pendingAmountStr","label":"未検収額","group":"V. 進捗・財務 (任意)","placeholder":"0"},{"name":"paymentConditionSummary","label":"支払条件","group":"V. 進捗・財務 (任意)","placeholder":"例: 検収月の翌月末日払い"},{"name":"CHANGE_RECORDS","label":"変更履歴","group":"V. 進捗・財務 (任意)","type":"textarea","placeholder":"2026-05-24|検収金額|100,000|80,000|一部不合格のため減額","helpText":"PDF の「変更履歴（当初発注条件からの変更）」に出力。複数件は ; 区切り。形式: 日付|項目名|変更前|変更後|理由"},{"name":"bankName","label":"金融機関","group":"VI. 振込先 (受託者口座, 任意)","dbField":"vendor.bank_name"},{"name":"branchName","label":"支店名","group":"VI. 振込先 (受託者口座, 任意)","dbField":"vendor.branch_name"},{"name":"accountType","label":"口座種別","group":"VI. 振込先 (受託者口座, 任意)","type":"select","options":["普通","当座"],"dbField":"vendor.account_type"},{"name":"accountNo","label":"口座番号","group":"VI. 振込先 (受託者口座, 任意)","dbField":"vendor.account_number"},{"name":"accountHolder","label":"口座名義","group":"VI. 振込先 (受託者口座, 任意)","dbField":"vendor.account_holder_kana"}]$json$::jsonb, 'initial import (Phase 1 / A2)', 'seed-templates'
FROM t
ON CONFLICT (template_id, version_no) DO NOTHING;

-- document: royalty_statement
WITH t AS (
  INSERT INTO document_templates (template_key, kind, label, category, comment)
  VALUES ('royalty_statement', 'document', '利用許諾料計算書', 'License', 'Phase 22.21.92: フォームを 4 ステップ動線に再構成。Backlog 系フィールド (manufacturingIssueKey / licenseIssueKey / linked_terms_number) は削除、計算結果は readonly。原著作物は ledger マスタから自動引用。詳細は templates_config.json (root) を参照。')
  ON CONFLICT (template_key) DO UPDATE
    SET label = EXCLUDED.label, category = EXCLUDED.category,
        comment = EXCLUDED.comment, kind = EXCLUDED.kind, updated_at = now()
  RETURNING id
)
INSERT INTO document_template_versions (template_id, version_no, html_source, field_schema, comment, created_by)
SELECT t.id, 1, $tpl$<!DOCTYPE html>
<html lang="ja">
<head>
  <meta charset="UTF-8">
  <title>利用許諾料計算書 {{DOC_NO}}</title>
  <style>
    @page { size: A4; margin: 14mm 16mm 14mm 16mm; }
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body {
      font-family: "Noto Sans CJK JP", "Noto Sans JP", "IPAexGothic", "IPAGothic", "MS Gothic", sans-serif;
      font-size: 10pt;
      color: #111;
      line-height: 1.55;
      word-break: break-word;
      overflow-wrap: anywhere;
    }

    /* ── ヘッダー (purchase_order と同形) ── */
    .header-row {
      display: flex;
      justify-content: space-between;
      align-items: flex-end;
      border-bottom: 2px solid #111;
      padding-bottom: 6px;
      margin-bottom: 14px;
    }
    .title-box h1 {
      font-size: 20pt;
      margin: 0;
      letter-spacing: 1.5px;
    }
    .doc-info {
      text-align: right;
      font-size: 9pt;
      line-height: 1.7;
      color: #555;
      white-space: nowrap;
    }
    .doc-info strong { color: #111; }

    /* ── 当事者 (2 列 + 挨拶文) ── */
    .party-grid {
      display: table;
      width: 100%;
      table-layout: fixed;
      margin-bottom: 12px;
    }
    .vendor-section {
      display: table-cell;
      vertical-align: top;
      font-size: 10pt;
      min-width: 0;
      padding-right: 12px;
    }
    .vendor-name {
      font-size: 13pt;
      font-weight: 800;
      border-bottom: 1px solid #111;
      display: inline-block;
      width: 100%;
      max-width: 100%;
      padding-bottom: 2px;
    }
    .company-section {
      display: table-cell;
      vertical-align: top;
      font-size: 9pt;
      background: #fafafa;
      padding: 10px;
      border: 1px solid #cfcfcf;
      width: 290px;
    }

    /* ── セクション見出し ── */
    .section-mark {
      color: #111;
      padding: 2px 0 2px 10px;
      font-weight: 800;
      font-size: 10pt;
      margin-top: 12px;
      margin-bottom: 6px;
      display: inline-block;
      border-left: 4px solid #111;
    }

    /* ── テーブル共通 ── */
    table { width: 100%; border-collapse: collapse; font-size: 9.5pt; }
    th {
      background: #f3f3f3;
      border: 1px solid #cfcfcf;
      padding: 6px 8px;
      font-weight: bold;
      text-align: center;
    }
    td { border: 1px solid #cfcfcf; padding: 6px 8px; }
    td.right { text-align: right; }
    td.center { text-align: center; }
    td.label { background: #f7f7f7; font-weight: bold; width: 160px; }

    /* ── 計算結果ハイライト ── */
    .result-box {
      border: 2px solid #111;
      padding: 12px 16px;
      margin: 14px 0;
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: 16px;
    }
    .result-item { flex: 1; text-align: center; }
    .result-item .label-sm { font-size: 8pt; color: #444; }
    .result-item .value-lg { font-size: 16pt; font-weight: bold; }
    .result-item .value-md { font-size: 13pt; font-weight: bold; }
    .result-divider { border-left: 1px solid #cfcfcf; height: 48px; }

    /* ── AG 進捗バー ── */
    .mg-bar-wrap {
      border: 1px solid #cfcfcf;
      padding: 8px 10px;
      margin-bottom: 12px;
    }
    .mg-bar-title { font-size: 8pt; color: #555; margin-bottom: 4px; }
    .mg-bar-track {
      height: 14px;
      background: #e8e8e8;
      border-radius: 2px;
      overflow: hidden;
      margin-bottom: 4px;
    }
    .mg-bar-fill { height: 100%; background: #444; }
    .mg-bar-labels {
      display: flex;
      justify-content: space-between;
      font-size: 7.5pt;
      color: #555;
    }

    /* ── 計算明細テーブルの行スタイル ── */
    tr.total-row td {
      background: #f0f0f0;
      font-weight: bold;
      font-size: 11pt;
    }
    tr.mg-row td { background: #fafafa; font-style: italic; color: #444; }
    tr.zero-row td { color: #888; }

    /* ── 備考ボックス ── */
    .notes-box {
      border: 1px solid #cfcfcf;
      background: #fff;
      padding: 8px 11px;
      font-size: 8.5pt;
      margin-top: 10px;
      line-height: 1.65;
    }

    /* ── フッター ── */
    .doc-footer {
      border-top: 1px solid #cfcfcf;
      padding-top: 6px;
      font-size: 7.5pt;
      color: #666;
      text-align: center;
      margin-top: 12px;
    }

    /* ── バッジ ── */
    .badge-consumed {
      display: inline-block;
      background: #222;
      color: #fff;
      font-size: 7.5pt;
      padding: 1px 6px;
      border-radius: 2px;
      margin-left: 6px;
      vertical-align: middle;
    }
    .badge-zero {
      display: inline-block;
      background: #888;
      color: #fff;
      font-size: 7.5pt;
      padding: 1px 6px;
      border-radius: 2px;
      margin-left: 6px;
      vertical-align: middle;
    }
  </style>
</head>
<body>

  {{!-- Phase 22.21.96: 発注書テンプレと同じ「挨拶形式」レイアウトに刷新。
        ・左にライセンサー名 + 担当者 + T番号 + 件名 + 拝啓〜の挨拶文
        ・右に発行元 (= ライセンシー = 自社) + 担当者情報をグレーボックスで
        ・ヘッダー右上に 文書番号 / 契約番号 / 発行日 --}}
  <div class="header-row">
    <div class="title-box">
      <h1>利用許諾料計算書</h1>
    </div>
    <div class="doc-info">
      文書番号: <strong>{{DOC_NO}}</strong><br>
      {{#if linked_contract_number}}契約番号: {{linked_contract_number}}<br>{{/if}}
      発行日: {{documentDate}}
    </div>
  </div>

  <div class="party-grid">
    {{!-- 左: ライセンサー (取引先) ──────────────────── --}}
    {{!-- Phase 22.21.97:
          ・LICENSOR_SUFFIX = 取引先 entity_type から判定 (法人→御中 / 個人→様)
          ・T番号 (licensor_t_number) は実 Backlog 課題キーのときだけ表示
            合成キー (LEGAL-* / IMPORT-* 等) は worker で空文字化される --}}
    <div class="vendor-section">
      {{!-- Phase 22.21.100: LICENSOR_SUFFIX はフォームで必ず set されるので
            旧 fallback (御中) を廃止。万一未 set の場合は何も付けない。 --}}
      <div class="vendor-name">{{licensor}}{{#if LICENSOR_SUFFIX}} {{LICENSOR_SUFFIX}}{{/if}}</div>
      {{#if VENDOR_REPRESENTATIVE_SAMA}}
      <div style="margin-top:6px; font-size:9.5pt;">{{VENDOR_REPRESENTATIVE_SAMA}}</div>
      {{/if}}
      {{#if licensor_t_number}}
      <div style="margin-top:6px; font-size:9pt; color:#555;">T番号: {{licensor_t_number}}</div>
      {{/if}}

      <div style="margin-top:12px; font-size:10.5pt;">
        件名: <strong>{{#if originalWork}}{{originalWork}} {{/if}}利用許諾料のご報告</strong>
      </div>

      <div style="margin-top:10px; line-height:1.8;">
        拝啓　平素は格別のお引き立てを賜り、厚く御礼申し上げます。<br>
        下記の通り利用許諾料を計算いたしましたので、ご査収のほどよろしくお願い申し上げます。
      </div>
    </div>

    {{!-- 右: ライセンシー = 発行元 (自社) ──────────── --}}
    <div class="company-section">
      <div style="font-size:8pt; font-weight:800; color:#555; margin-bottom:4px;">発行元 (ライセンシー)</div>
      <div style="font-weight:900; font-size:12pt; margin-bottom:5px;">{{licensee}}</div>
      {{#if STAFF_NAME}}
      <div style="margin-top:8px; padding-top:6px; border-top:1px dashed #cfcfcf; font-size:9pt;">
        {{#if STAFF_DEPARTMENT}}<strong>部署:</strong> {{STAFF_DEPARTMENT}}<br>{{/if}}
        <strong>担当:</strong> {{STAFF_NAME}}<br>
        {{#if STAFF_PHONE}}TEL: {{STAFF_PHONE}}<br>{{/if}}
        {{#if STAFF_EMAIL}}E-mail: {{STAFF_EMAIL}}{{/if}}
      </div>
      {{/if}}
    </div>
  </div>

  {{!-- ── 利用概要 ── --}}
  <div class="section-mark">■ 利用概要</div>
  <table style="margin-bottom:12px;">
    <tr>
      <td class="label">製品名</td>
      <td>{{productName}}{{#if edition}}（{{edition}}）{{/if}}</td>
      <td class="label" style="width:120px;">製造完了日</td>
      <td class="center" style="width:130px;"><strong>{{completionDate}}</strong></td>
    </tr>
    {{!-- Phase 28: 製造/印刷契機のみ数量系を表示。売上報告ベースは金額表記 --}}
    {{#if (eq calcType "manufacturing")}}
    <tr>
      <td class="label">製造数量（総数）</td>
      <td class="right">{{quantity}} 個</td>
      <td class="label">販促サンプル数</td>
      <td class="right">{{sampleQuantity}} 個（計算対象外）</td>
    </tr>
    <tr>
      <td class="label">課税対象数量</td>
      <td class="right"><strong>{{billableQuantity}} 個</strong></td>
      <td class="label">MSRP（税抜）</td>
      <td class="right">¥{{msrpStr}}</td>
    </tr>
    {{else}}
    <tr>
      <td class="label">{{#if (eq calcType "sublicense")}}被許諾者受領額{{else}}報告売上高{{/if}}（税抜）</td>
      <td class="right"><strong>¥{{msrpStr}}</strong></td>
      <td class="label">料率</td>
      <td class="right">{{royaltyRatePct}}%</td>
    </tr>
    {{/if}}
  </table>

  {{!-- ── ロイヤリティ計算明細 ── --}}
  <div class="section-mark">■ ロイヤリティ計算明細</div>
  <table style="margin-bottom:12px;">
    <thead>
      <tr>
        <th style="width:40%;">項目</th>
        <th style="width:30%;">計算式</th>
        <th style="width:30%;">金額（税抜）</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td>当期ロイヤリティ（グロス）</td>
        <td class="center">
          {{#if (eq calcType "manufacturing")}}
            {{billableQuantity}}個 × ¥{{msrpStr}} × {{royaltyRatePct}}%
          {{else if (eq calcType "sales")}}
            売上高 ¥{{msrpStr}} × {{royaltyRatePct}}%
          {{else if (eq calcType "sublicense")}}
            受領額 ¥{{msrpStr}} × {{royaltyRatePct}}%
          {{else}}
            固定額
          {{/if}}
        </td>
        <td class="right">¥{{grossRoyaltyStr}}</td>
      </tr>

      {{!-- Phase 22.21.95: MG (最低保証) = floor。グロス < MG のみ出す --}}
      {{#if mgTopupApplied}}
      <tr class="mg-row">
        <td>
          MG（最低保証）適用
          <span class="badge-consumed">FLOOR</span>
        </td>
        <td class="center">グロス ¥{{grossRoyaltyStr}} &lt; MG ¥{{mgAmountStr}} → MG を採用</td>
        <td class="right" style="color:#444;">+¥{{mgTopupThisTimeStr}}</td>
      </tr>
      {{/if}}

      {{!-- Phase 22.21.95: AG (前払い保証) = 消化型。ag_amount > 0 のみ出す --}}
      {{#if agApplied}}
      <tr class="mg-row">
        <td>
          AG（前払い保証金）充当
          {{#if agFullyConsumed}}<span class="badge-consumed">消化完了</span>{{/if}}
        </td>
        <td class="center">AG残高 ¥{{agConsumedBeforeStr}} → 今回 ▲¥{{agConsumedThisTimeStr}}</td>
        <td class="right" style="color:#444;">▲¥{{agConsumedThisTimeStr}}</td>
      </tr>
      {{/if}}

      <tr class="{{#if (eq actualRoyalty 0)}}zero-row{{else}}total-row{{/if}}">
        <td colspan="2">
          実支払ロイヤリティ
          {{#if (eq actualRoyalty 0)}}
            <span class="badge-zero">AG充当のため今期支払なし</span>
          {{/if}}
        </td>
        <td class="right">¥{{actualRoyaltyStr}}</td>
      </tr>

      {{#if actualRoyalty}}
      <tr>
        <td colspan="2" class="right">消費税（{{taxRate}}%）</td>
        <td class="right">¥{{taxAmount}}</td>
      </tr>
      <tr class="total-row">
        <td colspan="2" class="right">今期お支払合計（税込）</td>
        <td class="right">¥{{totalPaymentStr}}</td>
      </tr>
      {{/if}}
    </tbody>
  </table>

  {{!-- AG 進捗バー (AG > 0 のときのみ) --}}
  {{#if agApplied}}
  <div class="mg-bar-wrap">
    <div class="mg-bar-title">AG消化進捗（今回処理後）</div>
    <div class="mg-bar-track">
      <div class="mg-bar-fill" style="width: {{agProgressPct}}%;"></div>
    </div>
    <div class="mg-bar-labels">
      <span>消化済: ¥{{agConsumedAfterStr}} / AG総額: ¥{{agAmountStr}}</span>
      <span>残高: ¥{{agRemainingStr}}</span>
    </div>
  </div>
  {{/if}}

  {{!-- ── 支払条件・日程 ── --}}
  <div class="section-mark">■ 支払条件・日程</div>
  <table style="margin-bottom:12px;">
    <tr>
      <td class="label">支払条件</td>
      <td colspan="3">{{paymentConditionSummary}}</td>
    </tr>
    <tr>
      <td class="label">報告期限</td>
      <td><strong>{{reportingDeadline}}</strong></td>
      <td class="label" style="width:120px;">支払期日</td>
      <td class="center" style="width:140px;"><strong>{{paymentDueDate}}</strong></td>
    </tr>
    <tr>
      <td class="label">通貨</td>
      <td>{{currency}}</td>
      <td class="label">税率</td>
      <td class="center">{{taxRate}}%</td>
    </tr>
  </table>

  {{!-- Phase 22.21.103: 振込先口座 (取引先マスタから自動補完)。
        bankName / branchName / accountType / accountNo / accountHolder
        のいずれかが set されていればセクション全体を出す。 --}}
  {{#if (or bankName accountNo accountHolder)}}
  <div class="section-mark">■ 振込先口座 (取引先指定)</div>
  <table style="margin-bottom:12px;">
    <tr>
      <td class="label">金融機関</td>
      <td>{{bankName}}{{#if branchName}} {{branchName}}{{/if}}</td>
      <td class="label" style="width:120px;">口座種別</td>
      <td class="center" style="width:140px;">{{accountType}}</td>
    </tr>
    <tr>
      <td class="label">口座番号</td>
      <td><strong>{{accountNo}}</strong></td>
      <td class="label">口座名義 (カナ)</td>
      <td>{{accountHolder}}</td>
    </tr>
    {{#if invoiceRegistrationNumber}}
    <tr>
      <td class="label">インボイス登録番号</td>
      <td colspan="3">{{invoiceRegistrationNumber}}</td>
    </tr>
    {{/if}}
  </table>
  {{/if}}

  {{!-- ── 支払金額サマリー ── --}}
  {{#if actualRoyalty}}
  <div class="result-box">
    <div class="result-item">
      <div class="label-sm">今期お支払金額（税込）</div>
      <div class="value-lg">¥ {{totalPaymentStr}}</div>
    </div>
    <div class="result-divider"></div>
    <div class="result-item">
      <div class="label-sm">支払期日</div>
      <div class="value-md">{{paymentDueDate}}</div>
    </div>
    <div class="result-divider"></div>
    <div class="result-item">
      <div class="label-sm">報告期限</div>
      <div class="value-md">{{reportingDeadline}}</div>
    </div>
  </div>
  {{else}}
  <div class="result-box" style="background:#f8f8f8;">
    <div class="result-item">
      <div class="label-sm">今期実支払額</div>
      <div class="value-lg" style="color:#666;">¥ 0</div>
      <div class="label-sm" style="margin-top:4px;">AG充当のため今期のお支払はありません</div>
    </div>
    {{#if agApplied}}
    <div class="result-divider"></div>
    <div class="result-item">
      <div class="label-sm">AG残高</div>
      <div class="value-md">¥ {{agRemainingStr}}</div>
    </div>
    {{/if}}
  </div>
  {{/if}}

  {{!-- ── 備考 / みなし合意 / 連絡先 ── --}}
  <div class="notes-box">
    <div style="font-weight:bold; margin-bottom:4px;">備考</div>
    <div>※ 支払額は源泉徴収税引き後の金額になります。</div>
    <div style="margin-top:3px;">
      ※ 本計算書の内容に異議がある場合は、本書到達後 5 営業日以内に下記連絡先までご連絡ください。
      期限内にご連絡がない場合は、内容にご同意いただいたものとみなします。
    </div>
    <div style="margin-top:3px;">
      ※ 連絡先:
      {{#if STAFF_NAME}}{{STAFF_NAME}}{{else}}（担当者未設定）{{/if}}{{#if STAFF_DEPARTMENT}} ／ {{STAFF_DEPARTMENT}}{{/if}}{{#if STAFF_EMAIL}} ／ {{STAFF_EMAIL}}{{/if}}{{#if STAFF_PHONE}} ／ TEL {{STAFF_PHONE}}{{/if}}
    </div>
    {{#if notes}}
    <div style="margin-top:6px; padding-top:6px; border-top:1px dashed #ccc;">{{notes}}</div>
    {{/if}}
  </div>

  {{!-- Phase 22.21.99: 「LegalBridge により自動生成」フッターを削除
        (ユーザー要望)。doc-footer の CSS は他テンプレで使う可能性が
        あるため style ブロックには残置。 --}}

</body>
</html>
