-- document: sales_master_buyer
WITH t AS (
  INSERT INTO document_templates (template_key, kind, label, category, comment)
  VALUES ('sales_master_buyer', 'document', '売買基本契約書（当社買手版）', 'Sales', NULL)
  ON CONFLICT (template_key) DO UPDATE
    SET label = EXCLUDED.label, category = EXCLUDED.category,
        comment = EXCLUDED.comment, kind = EXCLUDED.kind, updated_at = now()
  RETURNING id
)
INSERT INTO document_template_versions (template_id, version_no, html_source, field_schema, comment, created_by)
SELECT t.id, 1, $tpl$<!DOCTYPE html>
<html lang="ja">
<head>
  <meta charset="UTF-8">
  <title>売買基本契約書（買手・アークライト版）- {{CONTRACT_NO}}</title>
  <style>
    @page {
      size: A4;
      margin: 18mm 20mm 22mm 25mm;
      @bottom-center {
        content: "- " counter(page) " -";
        font-size: 8.5pt;
        font-family: "Noto Serif CJK JP", "IPAMincho", serif;
      }
    }

    * { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: "Noto Serif CJK JP", "IPAMincho", "MS Mincho", serif;
      font-size: 10pt;
      line-height: 1.75;
      color: #000;
    }

    /* ===== ドキュメントヘッダー ===== */
    .doc-header {
      display: flex;
      justify-content: flex-end;
      align-items: baseline;
      margin-bottom: 0.5em;
    }

    .doc-header .contract-no {
      font-size: 8.5pt;
      color: #555;
      letter-spacing: 0.05em;
    }

    /* ===== タイトル ===== */
    h1.contract-title {
      text-align: center;
      font-size: 14pt;
      font-weight: bold;
      letter-spacing: 0.35em;
      margin-bottom: 0.9em;
      text-decoration: underline;
    }

    /* ===== 頭書き表 ===== */
    .tobogaki {
      width: 100%;
      border-collapse: collapse;
      margin-bottom: 1.4em;
      font-size: 9pt;
      line-height: 1.6;
      border-top: 1.5pt solid #1a1a1a;
      border-bottom: 1.5pt solid #1a1a1a;
    }

    .tobogaki th,
    .tobogaki td {
      border: none;
      border-bottom: 0.5pt solid #d8d8d8;
      padding: 0.45em 0.7em;
      vertical-align: top;
    }

    /* セクション見出し行 */
    .tobogaki .sec-row td {
      padding-top: 0.9em;
      padding-bottom: 0.25em;
      border-bottom: 0.5pt solid #888;
      font-size: 7.5pt;
      font-weight: bold;
      letter-spacing: 0.25em;
      color: #555;
      text-transform: uppercase;
    }

    /* 項目列 */
    .tobogaki .col-item {
      width: 36%;
      font-weight: bold;
      color: #1a1a1a;
      padding-left: 0.5em;
    }

    .tobogaki .col-item .art-ref {
      font-size: 7.5pt;
      font-weight: normal;
      color: #777;
    }

    .tobogaki .col-item .sub-note {
      display: block;
      font-size: 7.5pt;
      font-weight: normal;
      color: #888;
      margin-top: 0.1em;
    }

    /* 内容列 */
    .tobogaki .col-value {
      width: 64%;
      word-break: break-all;
      overflow-wrap: break-word;
      color: #1a1a1a;
    }

    /* 特記事項セル（全幅） */
    .tobogaki .special-cell {
      min-height: 2.5em;
      word-break: break-all;
      overflow-wrap: break-word;
      color: #1a1a1a;
    }

    /* ===== 前文 ===== */
    .preamble {
      font-size: 9.5pt;
      text-indent: 1em;
      margin-bottom: 0.9em;
      line-height: 1.7;
    }

    /* ===== 条文 ===== */
    ol.articles {
      list-style: none;
      padding: 0;
      counter-reset: article;
    }

    ol.articles > li {
      counter-increment: article;
      margin-bottom: 0.9em;
    }

    ol.articles > li > .article-title {
      font-weight: bold;
      font-size: 10pt;
      margin-bottom: 0.15em;
    }

    ol.articles > li > .article-title::before {
      content: "第" counter(article) "条";
    }

    ol.items {
      list-style: none;
      padding-left: 1.2em;
      counter-reset: item;
      font-size: 10pt;
    }

    ol.items > li {
      counter-increment: item;
      padding-left: 2em;
      text-indent: -2em;
      margin-bottom: 0.35em;
    }

    ol.items > li::before {
      content: counter(item) "　";
    }

    ol.sub-items {
      list-style: none;
      padding-left: 2em;
      counter-reset: subitem;
      margin-top: 0.25em;
    }

    ol.sub-items > li {
      counter-increment: subitem;
      padding-left: 2em;
      text-indent: -2em;
      margin-bottom: 0.25em;
    }

    ol.sub-items > li::before {
      content: "(" counter(subitem) ") ";
    }

    ol.sub-sub-items {
      list-style: none;
      padding-left: 2em;
      counter-reset: subsubitem;
      margin-top: 0.2em;
    }

    ol.sub-sub-items > li {
      counter-increment: subsubitem;
      padding-left: 2.5em;
      text-indent: -2.5em;
      margin-bottom: 0.2em;
    }

    ol.sub-sub-items > li::before {
      content: counter(subsubitem, katakana) "　";
    }

    /* ===== 余白・改ページ ===== */
    .margin-note {
      text-align: center;
      margin: 1.5em 0 2em;
      font-size: 9pt;
    }

    .page-break { page-break-after: always; }
    .no-break   { page-break-inside: avoid; }

    /* ===== 署名欄 ===== */
    .signature-block {
      margin-top: 2.5em;
      page-break-inside: avoid;
    }

    .signature-block .sig-intro {
      font-size: 9.5pt;
      margin-bottom: 1.2em;
      line-height: 1.7;
    }

    .signature-block .date-line {
      text-align: right;
      margin-bottom: 1.5em;
      font-size: 10pt;
    }

    .party {
      margin-bottom: 1.4em;
    }

    .party .party-label {
      font-weight: bold;
      margin-bottom: 0.25em;
    }

    .party .party-row {
      display: flex;
      margin-bottom: 0.2em;
    }

    .party .party-row .label {
      min-width: 4em;
    }

    .party .party-row .value {
      flex: 1;
      word-break: break-all;
    }
  </style>
</head>
<body>

<div class="doc-header">
  <span class="contract-no">契約番号：{{CONTRACT_NO}}</span>
</div>

<h1 class="contract-title">売買基本契約書</h1>

<!-- ======================================================
     頭書き（当事者目録・契約条件一覧）
     ====================================================== -->
<table class="tobogaki">
  <tbody>

    <!-- 当事者 -->
    <tr class="sec-row"><td colspan="2">当　事　者</td></tr>
    <tr>
      <td class="col-item">甲（買手）</td>
      <td class="col-value">
        東京都千代田区小川町１－２　風雲堂ビル２階<br>
        株式会社アークライト<br>
        代表取締役　青柳　昌行
      </td>
    </tr>
    <tr>
      <td class="col-item">乙（売手）</td>
      <td class="col-value">
        {{PARTY_B_ADDRESS}}<br>
        {{PARTY_B_NAME}}<br>
        {{PARTY_B_REPRESENTATIVE}}
      </td>
    </tr>

    <!-- 個別取引条件 -->
    <tr class="sec-row"><td colspan="2">個　別　取　引　条　件</td></tr>
    <tr>
      <td class="col-item">
        本製品の範囲<span class="art-ref">（第２条）</span>
        <span class="sub-note">未記載の場合は注文書による</span>
      </td>
      <td class="col-value">
        {{#if PRODUCT_SCOPE}}{{PRODUCT_SCOPE}}{{else}}注文書に定めるとおり{{/if}}
      </td>
    </tr>
    <tr>
      <td class="col-item">
        納入場所<span class="art-ref">（第５条）</span>
        <span class="sub-note">未記載の場合は注文書による</span>
      </td>
      <td class="col-value">
        {{#if DELIVERY_LOCATION}}{{DELIVERY_LOCATION}}{{else}}注文書に定めるとおり{{/if}}
      </td>
    </tr>
    <tr>
      <td class="col-item">
        支払条件<span class="art-ref">（第９条）</span>
        <span class="sub-note">未記載の場合は注文書による</span>
      </td>
      <td class="col-value">
        {{#if PAYMENT_CONDITION_SUMMARY}}{{PAYMENT_CONDITION_SUMMARY}}{{else}}注文書に定めるとおり{{/if}}
      </td>
    </tr>

    <!-- 手続・期間 -->
    <tr class="sec-row"><td colspan="2">手　続・期　間</td></tr>
    <tr>
      <td class="col-item">
        個別契約の承諾期限<span class="art-ref">（第３条第２項）</span>
        <span class="sub-note">注文書受領後に乙が承諾を要する期限</span>
      </td>
      <td class="col-value">{{#if ACCEPTANCE_PERIOD_DAYS}}注文書受領日から{{ACCEPTANCE_PERIOD_DAYS}}営業日以内{{else}}注文書記載のとおり{{/if}}</td>
    </tr>
    <tr>
      <td class="col-item">
        検収期間<span class="art-ref">（第８条第１項）</span>
        <span class="sub-note">納品後に甲が検査を完了すべき期間</span>
      </td>
      <td class="col-value">{{#if INSPECTION_PERIOD_DAYS}}納品後{{INSPECTION_PERIOD_DAYS}}営業日以内{{else}}注文書記載のとおり{{/if}}</td>
    </tr>
    <tr>
      <td class="col-item">
        不適合の追完期限<span class="art-ref">（第８条第２項）</span>
        <span class="sub-note">不適合通知受領後に乙が是正すべき期限</span>
      </td>
      <td class="col-value">{{#if INSPECTION_CURE_DAYS}}不適合通知の到達後{{INSPECTION_CURE_DAYS}}営業日以内{{else}}注文書記載のとおり{{/if}}</td>
    </tr>
    <tr>
      <td class="col-item">
        契約不適合責任期間<span class="art-ref">（第１１条）</span>
        <span class="sub-note">引渡し後に担保責任を追及できる期間</span>
      </td>
      <td class="col-value">{{#if WARRANTY_PERIOD}}引渡しから{{WARRANTY_PERIOD}}{{else}}注文書記載のとおり{{/if}}</td>
    </tr>
    <tr>
      <td class="col-item">
        契約違反の是正期間<span class="art-ref">（第１７条第１項）</span>
        <span class="sub-note">是正要求の通知受領後に対応すべき期限</span>
      </td>
      <td class="col-value">{{#if BREACH_CURE_DAYS}}是正要求の通知受領後{{BREACH_CURE_DAYS}}営業日以内{{else}}注文書記載のとおり{{/if}}</td>
    </tr>
    <tr>
      <td class="col-item">
        秘密保持期間<span class="art-ref">（第１３条・第２４条）</span>
        <span class="sub-note">契約終了後も義務が存続する期間</span>
      </td>
      <td class="col-value">{{#if CONFIDENTIALITY_YEARS}}本契約終了後{{CONFIDENTIALITY_YEARS}}年間{{else}}注文書記載のとおり{{/if}}</td>
    </tr>

    <!-- 管轄 -->
    <tr class="sec-row"><td colspan="2">管　　　　　轄</td></tr>
    <tr>
      <td class="col-item">合意管轄裁判所<span class="art-ref">（第２５条第２項）</span></td>
      <td class="col-value">{{JURISDICTION}}（第一審専属）</td>
    </tr>

    <!-- 特記事項（任意） -->
    {{#if SPECIAL_TERMS}}
    <tr class="sec-row"><td colspan="2">特　記　事　項</td></tr>
    <tr>
      <td colspan="2" class="special-cell">{{SPECIAL_TERMS}}</td>
    </tr>
    {{/if}}

  </tbody>
</table>

<!-- 前文 -->
<p class="preamble">
  頭書き記載の甲（株式会社アークライト。以下「甲」という。）と乙（以下「乙」という。）は、乙が取り扱う商品（以下「本製品」という。）の売買に関し、基本的事項を定めるため、以下のとおり契約（以下「本契約」という。）を締結する。
</p>

<!-- ======================================================
     条文本体
     ====================================================== -->
<ol class="articles">

  <!-- 第１条 -->
  <li>
    <div class="article-title">（本契約と個別契約）</div>
    <ol class="items">
      <li>本契約は、乙が取り扱う本製品を甲に売り渡し、甲がこれを買い受ける売買取引に関する基本的事項を定めるものであり、甲が乙に対して、物品の製造、加工、修理、情報成果物の作成又は役務の提供を委託することを目的とするものではない。</li>
      <li>本契約は、本製品にかかる個々の売買契約（以下「個別契約」という。）に共通して適用されるものとし、甲及び乙は、本契約及び個別契約を遵守する。</li>
      <li>本契約と個別契約の内容が相違する場合は、当該個別契約において本契約の特定の条項を変更又は排除する旨が明示されている場合に限り、当該個別契約の定めが優先する。</li>
      <li>見積書、注文請書、納品書、請求書その他乙が提示する書面又は電磁的記録に、甲の義務を加重し、又は甲の権利を制限する定めが含まれる場合であっても、甲が当該定めを明示的に承諾した場合を除き、当該定めは甲に対して効力を有しない。</li>
      <li>甲乙が個別契約において、製造委託、加工委託、修理委託、情報成果物の作成委託又は役務提供委託を明示的に定める場合には、当該個別契約又は別途締結する契約に従うものとする。</li>
    </ol>
  </li>

  <!-- 第２条 -->
  <li>
    <div class="article-title">（本製品の範囲）</div>
    <ol class="items">
      <li>本契約に基づき売買の対象となる本製品の範囲は、頭書きに定めるとおりとする。</li>
      <li>本製品の仕様、規格その他の詳細は、個別契約において定める。乙は、個別契約に定められた仕様・規格に適合した本製品を供給する義務を負う。</li>
    </ol>
  </li>

  <!-- 第３条 -->
  <li>
    <div class="article-title">（個別契約の成立）</div>
    <ol class="items">
      <li>個別契約は、甲が発行する注文書（発行年月日、品名、仕様、単価、数量、合計金額、納入期日、納入場所その他必要事項を記載したものをいう。）を乙に送付し、乙が注文請書、電子メールその他の書面又は電磁的方法によりこれを承諾した時点で成立する。</li>
      <li>乙が注文書の内容に基づき、本製品の出荷、納品その他履行に着手した場合、乙は当該注文書の内容を承諾したものとみなす。</li>
      <li>乙は、注文書を受領した日から頭書きに定める承諾期限（頭書きに記載のない場合は注文書記載のとおり）以内に、承諾又は異議の意思表示を行うものとする。当該期間内に乙から異議の通知がなく、かつ、当事者間の従前の取引慣行その他の事情に照らして合理的と認められる場合には、乙は当該注文書の内容を承諾したものとみなす。</li>
      <li>前各項の規定は、甲及び乙が協議の上でこれに代わる個別契約の成立方法を定めることを妨げない。</li>
    </ol>
  </li>

  <!-- 第４条 -->
  <li>
    <div class="article-title">（供給義務・安定供給）</div>
    <ol class="items">
      <li>乙は、個別契約に定める品名・仕様・数量の本製品を、指定された納入期日までに甲に安定的に供給する義務を負う。</li>
      <li>乙は、原材料の調達難、製造設備の故障その他の事由により本製品の供給が困難となるおそれが生じた場合、直ちに甲にその旨を書面または電子的手段により通知し、甲と協議のうえ代替措置を講じなければならない。</li>
    </ol>
  </li>

  <!-- 第５条 -->
  <li>
    <div class="article-title">（納品）</div>
    <ol class="items">
      <li>乙は、個別契約に定める納入期日までに、頭書き又は注文書に定める納入場所に本製品を納品するものとする。</li>
      <li>本製品の納品は、乙が甲の指定する納入場所に本製品を搬入し、甲又は甲の指定する者がこれを物理的に受領した時点で完了する。ただし、当該受領は、数量、品質、仕様その他契約適合性について甲が承認したことを意味しない。</li>
      <li>納品に要する費用（運送料、梱包費、保険料その他納品に通常必要となる費用を含む。）は、特段の合意がない限り乙の負担とする。</li>
      <li>乙は、納品の際に、品名、数量、仕様その他甲が合理的に必要と認める事項を記載した納品書を添付しなければならない。</li>
    </ol>
  </li>

  <!-- 第６条 -->
  <li>
    <div class="article-title">（所有権の移転）</div>
    <ol class="items">
      <li>本製品の所有権は、甲による検収が完了した時点で、乙から甲に移転する。ただし、個別契約において別段の定めがある場合は、当該定めに従う。</li>
    </ol>
  </li>

  <!-- 第７条 -->
  <li>
    <div class="article-title">（危険負担）</div>
    <ol class="items">
      <li>本製品の検収完了前に生じた本製品の滅失、毀損、変質その他一切の危険は、甲の責めに帰すべき事由による場合を除き、乙の負担とする。</li>
      <li>本製品の検収完了後に生じた本製品の滅失、毀損、変質その他一切の危険は、乙の責めに帰すべき事由による場合を除き、甲の負担とする。</li>
      <li>前２項の定めにかかわらず、本製品に契約不適合がある場合、又は乙の梱包、表示、輸送手配その他乙の責めに帰すべき事由により本製品に滅失、毀損、変質その他の問題が生じた場合には、乙がその責任を負う。</li>
    </ol>
  </li>

  <!-- 第８条 -->
  <li>
    <div class="article-title">（検品及び検収）</div>
    <ol class="items">
      <li>甲は、本製品の納品後、頭書きに定める検収期間（頭書きに記載のない場合は注文書記載のとおり）以内に、甲が定める方法により本製品の検査を行う。</li>
      <li>前項の検査の結果、本製品の種類、品質、数量、仕様その他の内容が本契約又は個別契約の内容に適合しないこと（以下「不適合」という。）が判明した場合、甲は乙に対し、当該不適合の内容を、書面又は電子的手段により通知するものとする。</li>
      <li>乙は、前項の通知を受領した場合、頭書きに定める追完期限（頭書きに記載のない場合は注文書記載のとおり）以内に、甲が指定する方法により、修補、代替品の引渡し、不足分の引渡しその他必要な履行の追完を行わなければならない。</li>
      <li>前項の追完が困難である場合、又は追完によっても本契約若しくは個別契約の目的を達することができない場合、甲は、代金の減額、損害賠償、個別契約の解除その他法令及び本契約に基づき認められる措置を請求することができる。</li>
      <li>検収期間内に甲から不適合の通知がない場合、本製品は検査に合格したものとみなす。ただし、検査によって直ちに発見することが困難な不適合については、この限りでない。</li>
      <li>本製品が第１項の検査に合格した時点又は前項本文により合格したものとみなされた時点をもって、検収完了とする。</li>
    </ol>
  </li>

  <!-- 第９条 -->
  <li>
    <div class="article-title">（支払方法）</div>
    <ol class="items">
      <li>甲は、乙に対し、個別契約に基づく本製品の代金を、頭書きまたは注文書に定める支払条件により、乙が指定する銀行口座へ振込みにて支払うものとする。振込手数料は甲の負担とする。</li>
      <li>乙は、支払期日の到来した請求書を、甲が定める様式に従い、締日後速やかに甲に発行するものとする。</li>
      <li>甲は、乙に対して有する反対債権がある場合、支払期日前であっても相殺をもって代金の支払に充当することができる。</li>
    </ol>
  </li>

  <!-- 第１０条 -->
  <li>
    <div class="article-title">（知的財産権等の保証）</div>
    <ol class="items">
      <li>乙は、甲に対し、本製品（その製造・販売・使用を含む。）が第三者の特許権、実用新案権、商標権、意匠権、著作権、肖像権・プライバシーの権利その他の知的財産権及びその他の権利を侵害しないことを保証する。</li>
      <li>本製品が第三者の権利を侵害したとして第三者から甲に対しクレーム、訴訟その他の請求がなされた場合、乙は自己の費用と責任においてこれを処理し、甲を免責するものとする。甲が当該請求に対応するために費用を支出した場合、乙はこれを甲に賠償する。</li>
    </ol>
  </li>

  <!-- 第１１条 -->
  <li>
    <div class="article-title">（契約不適合責任）</div>
    <ol class="items">
      <li>本製品に不適合がある場合、甲は乙に対し、次の各号に定める請求のいずれか又はその組合せを、甲の選択により行うことができる。
        <ol class="sub-items">
          <li>履行の追完（修補、代替品の引渡し又は不足分の引渡しを含む。）</li>
          <li>代金の減額</li>
          <li>損害賠償</li>
          <li>個別契約の全部又は一部の解除</li>
          <li>その他法令又は本契約に基づき認められる措置</li>
        </ol>
      </li>
      <li>甲は、検査により発見された不適合については、第８条に定める検収期間内に乙へ通知するものとする。</li>
      <li>甲は、検査によって直ちに発見することが困難な不適合については、頭書きに定める契約不適合責任期間内に発見し、かつ、発見後相当期間内に乙へ通知することにより、前項に定める権利を行使することができる。</li>
      <li>前項の通知がなされた場合、甲の追完請求、代金減額請求、損害賠償請求及び解除権の行使期間は、民法、商法その他適用法令の定めに従う。</li>
      <li>乙は、不適合が甲の責めに帰すべき事由によるものであることを証明した場合に限り、本条に定める責任を免れる。</li>
    </ol>
  </li>

  <!-- 第１２条 -->
  <li>
    <div class="article-title">（製造物責任等）</div>
    <ol class="items">
      <li>甲又は乙は、本製品の欠陥、不適合、安全性、表示、取扱説明その他本製品に関して第三者との間で紛議、請求、行政対応その他の問題が生じた場合、直ちに相手方に通知し、相互に協力して当該問題の解決にあたるものとする。</li>
      <li>本製品の設計、製造、加工、梱包、表示、取扱説明、警告表示その他乙が関与した事項に起因して、本製品に欠陥、不適合又は安全上の問題が生じた場合、乙は自己の費用と責任において、第三者からの請求、行政対応、回収、交換、返金、廃棄その他必要な措置を行うものとする。</li>
      <li>前項の場合、乙は、甲に生じた損害、費用及び負担を賠償するものとする。当該損害等には、甲が第三者に支払った賠償金、返金額、回収費用、廃棄費用、調査費用、弁護士費用その他合理的に発生した費用を含む。</li>
    </ol>
  </li>

  <!-- 第１３条 -->
  <li>
    <div class="article-title">（秘密保持）</div>
    <ol class="items">
      <li>甲及び乙は、本契約及び個別契約の存在及び各条項並びに本契約及び個別契約に関連して知った相手方に関する情報（以下「秘密情報」という。）を、相手方の書面による事前の承諾なく第三者に対して開示、提供又は漏洩してはならない。ただし、次のいずれかに該当することを証明できる情報については、秘密情報から除くものとする。
        <ol class="sub-items">
          <li>提供又は開示を受けた際、既に自己が保有していた情報</li>
          <li>提供又は開示を受けた際、既に公知となっている情報</li>
          <li>提供又は開示を受けた後、自己の責めによらずに公知となった情報</li>
          <li>正当な権限を有する第三者から秘密保持義務を負わずに適法に取得した情報</li>
          <li>秘密情報によることなく独自に開発又は取得した情報</li>
          <li>法令の規定又は権限ある官公庁からの開示の要求に基づき開示しなければならない情報</li>
        </ol>
      </li>
      <li>甲及び乙は、秘密情報を本契約又は個別契約の目的以外に使用してはならない。</li>
      <li>甲及び乙は、秘密情報を、本契約又は個別契約の遂行のために知る必要のある自己の役員及び従業員並びに弁護士等の法令上守秘義務を負う専門家に限り開示することができる。この場合、本条と同等の義務を当該役員等に退職後も含め課さなければならない。</li>
      <li>本契約が終了した場合、甲及び乙は、相手方の指示に従って秘密情報を返還し、又は破棄するものとする。</li>
    </ol>
  </li>

  <!-- 第１４条 -->
  <li>
    <div class="article-title">（個人情報）</div>
    <ol class="items">
      <li>甲及び乙は、本契約又は個別契約に関連して取得した個人情報（個人情報の保護に関する法律に定める個人情報をいう。）を法令及び適用あるガイドラインに従い、適切に管理しなければならない。</li>
    </ol>
  </li>

  <!-- 第１５条 -->
  <li>
    <div class="article-title">（遅延損害金）</div>
    <ol class="items">
      <li>甲及び乙は、本契約又は個別契約に基づく債務の支払を遅滞したときは、相手方に対し、当該債務の支払期日の翌日から支払済みまで年１４．６％（年３６５日の日割計算）の割合による遅延損害金を支払わなければならない。</li>
    </ol>
  </li>

  <!-- 第１６条 -->
  <li>
    <div class="article-title">（通知）</div>
    <ol class="items">
      <li>本契約に基づく通知、承諾その他の連絡は、当事者が事前に相手方に対して書面または電子的手段により指定した通知先に対して、書留速達郵便、ファクシミリ、電子メール、又は当事者間で合意されたその他の手段により行うものとする。</li>
      <li>両当事者は、自らの通知先を変更する場合、相手方に対してその旨を速やかに通知するものとし、当該通知が相手方に到達した時点以降、当該変更は有効となる。</li>
    </ol>
  </li>

  <!-- 第１７条 -->
  <li>
    <div class="article-title">（解除等）</div>
    <ol class="items">
      <li>甲又は乙が本契約又は個別契約のいずれかの条項に違反し、相手方からその是正を要求する通知を受領した後、頭書きに定める是正期間（頭書きに記載のない場合は注文書記載のとおり）以内にその違反を是正しない場合、相手方は、本契約又は当該個別契約の全部又は一部を解除することができる。</li>
      <li>甲又は乙は、相手方が以下の各号に定める事由のいずれかに該当した場合には、何らの催告を要することなく、直ちに本契約又は個別契約の全部又は一部を解除することができる。
        <ol class="sub-items">
          <li>重大な過失又は背信行為があったとき</li>
          <li>手形若しくは小切手の不渡りが生じたとき、電子交換所の取引停止処分を受けたとき、又は支払停止の状態に陥ったとき</li>
          <li>第三者より仮差押え、仮処分、強制執行等を受けたとき、又は公租公課の滞納処分を受けたとき</li>
          <li>破産手続、特別清算、民事再生手続又は会社更生手続開始の申立てがあったとき</li>
          <li>債務整理の通知がなされたとき</li>
          <li>財務状態が著しく悪化し、又は悪化のおそれがあると認められるとき</li>
          <li>その他前各号に準ずるような、本契約又は個別契約を継続し難い重大な事由が発生したとき</li>
        </ol>
      </li>
      <li>甲は、前２項に定めるほか、事業上の必要がある場合、乙に対して書面又は電磁的方法により通知することで、未履行部分に限り、個別契約の全部又は一部を解除又は変更することができる。</li>
      <li>前項の場合において、乙が既に本製品の出荷、納品その他履行に着手しているときは、甲乙協議の上、既履行部分、出荷済み製品その他合理的に精算すべき事項について精算するものとする。</li>
    </ol>
  </li>

  <!-- 第１８条 -->
  <li>
    <div class="article-title">（期限の利益喪失）</div>
    <ol class="items">
      <li>甲又は乙は、本契約又は個別契約のいずれかの条項に違反した場合、相手方からの書面による通知により、本契約又は個別契約に基づき相手方に対して負う一切の債務について期限の利益を失い、相手方に対し、直ちに当該債務を履行しなければならない。</li>
      <li>甲又は乙は、前条第２項各号に該当した場合、相手方からの通知を要することなく当然に期限の利益を失い、相手方に対し、直ちに当該債務を履行しなければならない。</li>
    </ol>
  </li>

  <!-- 第１９条 -->
  <li>
    <div class="article-title">（通知義務）</div>
    <ol class="items">
      <li>本契約の当事者は、自ら又は本契約に関して次の各号のいずれかに該当する事由が発生し、又は発生するおそれが生じたことを認識したときは、相手方に対して速やかにその旨を通知しなければならない。
        <ol class="sub-items">
          <li>会社支配権の変動</li>
          <li>解散、合併、会社分割、株式交換、株式移転及び株式交付その他の組織再編、事業譲渡及び事業の譲受け並びに組織変更</li>
          <li>資本金又は資本準備金の額の減少</li>
          <li>破産、民事再生、及び会社更生その他の倒産手続の申立て又は開始</li>
          <li>業務停止その他の行政処分</li>
          <li>本契約に基づく取引に関連する第三者からのクレーム</li>
        </ol>
      </li>
    </ol>
  </li>

  <!-- 第２０条 -->
  <li>
    <div class="article-title">（損害賠償）</div>
    <ol class="items">
      <li>甲又は乙が本契約又は個別契約に違反した場合、当該当事者は、相手方に対し、当該違反により相手方に生じた損害を賠償する責任を負う。</li>
      <li>乙が本製品の供給義務、第１０条に定める知的財産権等の保証義務、第１１条に定める契約不適合責任又は第１２条に定める製造物責任等に違反したことにより甲に損害が生じた場合、乙は当該損害を甲に賠償するものとする。</li>
      <li>前項の損害には、甲が代替品の調達のために要した費用、回収費用、交換費用、返金対応費用、第三者対応費用、弁護士費用その他合理的に発生した費用を含む。</li>
    </ol>
  </li>

  <!-- 第２１条 -->
  <li>
    <div class="article-title">（有効期間）</div>
    <ol class="items">
      <li>本契約の有効期間は、本契約締結の日から１年間とする。ただし、期間満了の１か月前までに甲乙いずれからも何ら書面による申出がないときは、更に１年間延長されるものとし、以後も同様とする。</li>
    </ol>
  </li>

  <!-- 第２２条 -->
  <li>
    <div class="article-title">（反社会的勢力の排除）</div>
    <ol class="items">
      <li>甲及び乙は、相互に、次の各号に定める事項について表明保証し、かつ、誓約する。
        <ol class="sub-items">
          <li>自らが反社会的勢力（その名称にかかわらず、暴力団、暴力団員、暴力団準構成員、暴力団関係企業、総会屋、社会運動標榜ゴロ、政治活動標榜ゴロ、特殊知能暴力集団及びこれらに準じるものをいい、反社会的勢力でなくなった時から５年を経過しないものも反社会的勢力とみなす。以下同じ。）に該当せず、また将来に渡って反社会的勢力に該当しないこと。</li>
          <li>反社会的勢力との間で、直接又は間接を問わず、資本上の関係を有していないこと及び今後も有しないこと。</li>
          <li>反社会的勢力に対し、直接又は間接を問わず、資金の提供を行っていないこと及び今後も行わないこと。</li>
          <li>反社会的勢力を役員に選任しておらず、かつ、従業員として雇用していないこと及び今後も選任又は雇用しないこと。</li>
          <li>反社会的勢力が、直接又は間接を問わず、自らの経営に関与していないこと及び今後も関与させないこと。</li>
          <li>直接又は間接を問わず、次に掲げる行為を行っていないこと及び今後も行わないこと。
            <ol class="sub-sub-items">
              <li>相手方又は第三者に対する脅迫的な言動又は暴力を用いる行為</li>
              <li>偽計又は威力を用いて相手方又は第三者の業務を妨害し、又は、信用を毀損する行為</li>
              <li>相手方又は第三者に対する違法な要求行為</li>
              <li>その他、前アからウまでに準ずる行為</li>
            </ol>
          </li>
        </ol>
      </li>
      <li>甲及び乙は、自らが前項各号に定める事項に違反し、又は、違反するおそれがあると判断した場合は、相手方に対し、直ちにその旨を通知しなければならない。</li>
      <li>甲及び乙は、相手方が第１項各号の規定又は前項の通知義務に違反すると合理的に判断した場合は、何らの通知又は催告を要せず、かつ、何らの賠償義務を負わず、甲乙間の全部又は一部の契約を直ちに終了させることができる。</li>
    </ol>
  </li>

  <!-- 第２３条 -->
  <li>
    <div class="article-title">（本契約及び個別契約上の地位譲渡等の禁止）</div>
    <ol class="items">
      <li>甲及び乙は、相手方の書面による事前の承諾がない限り、本契約及び個別契約上の権利及び義務並びに地位を第三者へ譲渡し、又は担保に供してはならない。</li>
    </ol>
  </li>

  <!-- 第２４条 -->
  <li>
    <div class="article-title">（存続）</div>
    <ol class="items">
      <li>本契約が終了した場合でも、第１０条（知的財産権等の保証）、第１１条（契約不適合責任）、第１２条（製造物責任等）、第１３条（秘密保持）、第１４条（個人情報）、第１５条（遅延損害金）、第２０条（損害賠償）、第２２条（反社会的勢力の排除）、第２３条（本契約及び個別契約上の地位譲渡等の禁止）、第２５条（準拠法及び専属的合意管轄裁判所）並びに第２６条（協議）は、その性質上又は本条の定めに従い、本契約終了後も有効に存続する。ただし、第１３条（秘密保持）については、頭書きに定める秘密保持期間（頭書きに記載のない場合は注文書記載のとおり）に限り、その効力を有する。</li>
    </ol>
  </li>

  <!-- 第２５条 -->
  <li>
    <div class="article-title">（準拠法および専属的合意管轄裁判所）</div>
    <ol class="items">
      <li>本契約及び個別契約の成立、効力、解釈及び履行については、日本法を準拠法とする。</li>
      <li>本契約に関する紛争については、頭書きに定める合意管轄裁判所を第一審の専属的合意管轄裁判所とする。</li>
    </ol>
  </li>

  <!-- 第２６条 -->
  <li>
    <div class="article-title">（協議）</div>
    <ol class="items">
      <li>本契約および個別契約に定められていない事項または解釈上疑義が生じた事項については、その都度、甲乙誠意をもって協議決定する。</li>
    </ol>
  </li>

</ol><!-- /articles -->

<div class="margin-note">（以下余白）</div>

<!-- ======================================================
     署名欄（末尾）
     ====================================================== -->
<div class="signature-block no-break">
  <p class="sig-intro">本契約締結の証として、本書２通を作成し、甲乙記名押印のうえ、各１通を保有又は、本書の電磁的記録を作成し、甲乙合意の後電子署名を施し、各自その電磁的記録を保管する。</p>

  <div class="date-line">締結日：{{CONTRACT_DATE_FORMATTED}}</div>

  <!-- 甲（買手・アークライト） -->
  <div class="party">
    <div class="party-label">甲</div>
    <div class="party-row">
      <span class="label">所在地　</span>
      <span class="value">東京都千代田区小川町１－２　風雲堂ビル２階</span>
    </div>
    <div class="party-row">
      <span class="label">会社名　</span>
      <span class="value">株式会社アークライト</span>
    </div>
    <div class="party-row">
      <span class="label">代表者　</span>
      <span class="value">代表取締役　青柳　昌行　　　　　㊞</span>
    </div>
  </div>

  <!-- 乙（売手・相手方） -->
  <div class="party">
    <div class="party-label">乙</div>
    <div class="party-row">
      <span class="label">所在地　</span>
      <span class="value">{{PARTY_B_ADDRESS}}</span>
    </div>
    <div class="party-row">
      <span class="label">会社名　</span>
      <span class="value">{{PARTY_B_NAME}}</span>
    </div>
    <div class="party-row">
      <span class="label">代表者　</span>
      <span class="value">{{PARTY_B_REPRESENTATIVE}}　　　　　㊞</span>
    </div>
  </div>
</div>

</body>
</html>
$tpl$, $json$[{"name":"CONTRACT_NO","label":"契約番号","group":"I. ヘッダ","dbField":"auto.docNumber","helpText":"📌 PDF 右上「契約番号：__」に出ます\n生成時に自動採番 (空欄でも可)"},{"name":"CONTRACT_DATE_FORMATTED","label":"契約締結日","group":"I. ヘッダ","required":true,"placeholder":"例: 2026年5月12日","helpText":"📌 PDF 署名欄上部「__」の日付に出ます\n年月日を「2026年5月12日」のように 全角/半角どちらでも可"},{"name":"PARTY_B_NAME","label":"乙 (売主) 名称","group":"II. 乙 (売主・取引先)","required":true,"helpText":"📌 PDF 頭書 + 第26条署名「乙 会社名」に出ます\n[取引先] ボタンで自動入力 / 甲はテンプレ内『株式会社アークライト』固定"},{"name":"PARTY_B_ADDRESS","label":"乙 住所","group":"II. 乙 (売主・取引先)","type":"textarea","required":true,"helpText":"📌 PDF 署名欄「乙 所在地」に出ます"},{"name":"PARTY_B_REPRESENTATIVE","label":"乙 代表者","group":"II. 乙 (売主・取引先)","required":true,"placeholder":"例: 代表取締役 山田 太郎","helpText":"📌 PDF 署名欄「乙 代表者」+ ㊞ 印影マークに出ます"},{"name":"PRODUCT_SCOPE","label":"本製品の範囲","group":"III. 取引条件","type":"textarea","placeholder":"例: 乙が取扱うアナログゲーム製品全般","helpText":"📌 第2条「本契約に基づき売買の対象となる本製品の範囲は、__とする」に挿入\n空欄なら『個別契約 (注文書) に定めるとおりとする』と自動描画"},{"name":"DELIVERY_LOCATION","label":"納入場所","group":"III. 取引条件","placeholder":"例: 甲指定の倉庫","helpText":"📌 第5条「注文書に定める納品場所 (__)」に挿入\n空欄なら『注文書に定める納品場所』と自動描画"},{"name":"ACCEPTANCE_PERIOD_DAYS","label":"受入確認期間 (営業日・任意)","group":"III. 取引条件","type":"number","placeholder":"例: 10","helpText":"📌 第3条「注文書受領日から __ 営業日以内」に挿入\n→ 注文書受領後に乙が承諾を要する期限。\n空欄なら『注文書記載のとおり』とフォールバック描画。"},{"name":"INSPECTION_PERIOD_DAYS","label":"検査通知期間 (営業日・任意)","group":"III. 取引条件","type":"number","placeholder":"例: 10","helpText":"📌 第8条「納品後 __ 営業日以内」に挿入\n→ 納品後に甲が検査を完了すべき期間。\n空欄なら『注文書記載のとおり』とフォールバック描画。"},{"name":"INSPECTION_CURE_DAYS","label":"検査不合格時の是正期間 (営業日・任意)","group":"III. 取引条件","type":"number","placeholder":"例: 10","helpText":"📌 第8条「不適合通知の到達後 __ 営業日以内」に挿入\n→ 不適合通知受領後に乙が是正すべき期限。\n空欄なら『注文書記載のとおり』とフォールバック描画。"},{"name":"WARRANTY_PERIOD","label":"契約不適合 保証期間","group":"III. 取引条件","required":true,"placeholder":"例: 引渡し後1年","helpText":"📌 第11条「引渡し後 __ 以内に発見された場合」+「引渡しから __ を超えて行使することはできない」の 2 箇所に挿入\n→ 隠れた瑕疵を含む契約不適合の追完請求権が行使可能な期間"},{"name":"PAYMENT_CONDITION_SUMMARY","label":"支払条件","group":"III. 取引条件","placeholder":"例: 月末締め翌月末日払い","helpText":"📌 第9条「__により、乙が指定する銀行口座へ振込みにて支払う」に挿入\n空欄なら『注文書に定める支払条件』と自動描画"},{"name":"BREACH_CURE_DAYS","label":"契約違反時の是正催告期間 (営業日)","group":"III. 取引条件","type":"number","required":true,"placeholder":"14","helpText":"📌 契約違反通知後の是正猶予期間。例: 14 営業日"},{"name":"CONFIDENTIALITY_YEARS","label":"秘密保持期間 (年)","group":"IV. 一般条項","type":"number","required":true,"placeholder":"5","helpText":"📌 第24条「第13条 (秘密保持) については、本契約の終了後 __ 年間に限り、その効力を有する」に挿入\n→ 契約終了後も機密保持義務が継続する年数。一般的には 3〜5 年"},{"name":"JURISDICTION","label":"合意管轄","group":"IV. 一般条項","required":true,"placeholder":"例: 東京地方裁判所","helpText":"📌 第25条「本契約に関する紛争については、__ を第一審の専属的合意管轄裁判所とする」に挿入\n→ 訴訟の第一審管轄。当社の場合は 東京地方裁判所 が一般的"},{"name":"SPECIAL_TERMS","label":"特約事項","group":"V. 特約 (任意)","type":"textarea","helpText":"📌 PDF 末尾 (署名欄の前) に「【特記事項】」ブロックで囲み枠付きで挿入\n空欄なら該当ブロックは PDF に出力されません"}]$json$::jsonb, 'initial import (Phase 1 / A2)', 'seed-templates'
