INSERT INTO document_template_versions (template_id, version_no, html_source, field_schema, comment, created_by)
SELECT t.id, 1, $tpl${{!--
  legal_response.html — Phase 22.21.84
  ユーザー提供デザインを Handlebars 化したもの。

  使用変数 (templates_config.json: legal_response):
    {{DOC_NO}}          自動採番された文書番号 (例: ARC-LG-2026-0001)
    {{RESPONSE_DATE}}   回答日
    {{CONSULTER_DEPT}}  相談部署
    {{CONSULTER_NAME}}  相談者
    {{SUBJECT}}         件名
    {{RESPONSE_AUTHOR}} 回答担当者 (default: 法務部次長 倉持 達也)
    {{QUESTION_1}}      Q1 質問 (必須)
    {{ANSWER_1}}        A1 回答 (必須)
    {{QUESTION_2}}      Q2 質問 (任意、空ならブロック非表示)
    {{ANSWER_2}}        A2 回答
    {{QUESTION_3}}      Q3 質問 (任意)
    {{ANSWER_3}}        A3 回答
--}}
<!DOCTYPE html>
<html lang="ja">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>法務相談 回答書 {{DOC_NO}}</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    font-family: 'Helvetica Neue', Arial, 'Hiragino Kaku Gothic ProN', 'Meiryo', sans-serif;
    background: #fff;
    color: #111;
    font-size: 13px;
    line-height: 1.7;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  .page {
    max-width: 794px;
    margin: 0 auto;
    padding: 48px 52px 64px;
  }

  /* ── Header ── */
  .doc-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
    border-bottom: 2px solid #111;
    padding-bottom: 12px;
    margin-bottom: 40px;
  }
  .doc-header .org {
    font-size: 10px;
    letter-spacing: 0.12em;
    color: #666;
    text-transform: uppercase;
  }
  .doc-header .doc-id {
    font-size: 10px;
    color: #888;
    letter-spacing: 0.06em;
  }

  /* ── Title ── */
  .doc-title {
    margin-bottom: 36px;
  }
  .doc-title h1 {
    font-size: 26px;
    font-weight: 700;
    letter-spacing: 0.05em;
    line-height: 1.2;
    margin-bottom: 4px;
  }
  .doc-title .subtitle {
    font-size: 10px;
    letter-spacing: 0.2em;
    color: #888;
    text-transform: uppercase;
  }

  /* ── Meta table ── */
  .meta-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 44px;
    font-size: 12px;
  }
  .meta-table tr {
    border-bottom: 0.5px solid #e0e0e0;
  }
  .meta-table tr:first-child {
    border-top: 0.5px solid #e0e0e0;
  }
  .meta-table td {
    padding: 8px 12px;
    vertical-align: top;
  }
  .meta-table .label {
    width: 120px;
    color: #888;
    font-weight: 500;
    letter-spacing: 0.04em;
    white-space: nowrap;
  }
  .meta-table .value {
    color: #111;
  }

  /* ── Divider ── */
  .section-divider {
    border: none;
    border-top: 0.5px solid #ccc;
    margin: 36px 0;
  }

  /* ── Q&A block ── */
  .qa-block {
    margin-bottom: 36px;
  }
  .qa-number {
    font-size: 10px;
    font-weight: 700;
    letter-spacing: 0.18em;
    color: #999;
    text-transform: uppercase;
    margin-bottom: 10px;
  }

  .question-box {
    border-left: 3px solid #111;
    padding: 14px 16px;
    background: #f7f7f7;
    margin-bottom: 16px;
  }
  .question-box .box-label {
    font-size: 9px;
    letter-spacing: 0.2em;
    font-weight: 700;
    color: #999;
    text-transform: uppercase;
    margin-bottom: 6px;
  }
  .question-box .content {
    font-size: 13px;
    color: #222;
    min-height: 18px;
    /* Phase 22.21.84: form 入力の改行をそのまま PDF に反映 */
    white-space: pre-wrap;
    word-wrap: break-word;
  }

  .answer-box {
    border-left: 3px solid #111;
    padding: 14px 16px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-left: 3px solid #111;
  }
  .answer-box .box-label {
    font-size: 9px;
    letter-spacing: 0.2em;
    font-weight: 700;
    color: #555;
    text-transform: uppercase;
    margin-bottom: 6px;
  }
  .answer-box .content {
    font-size: 13px;
    color: #111;
    min-height: 72px;
    white-space: pre-wrap;
    word-wrap: break-word;
  }

  /* ── Footer note ── */
  .doc-footer {
    margin-top: 52px;
    padding-top: 16px;
    border-top: 0.5px solid #ccc;
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 16px;
  }
  .doc-footer .note {
    font-size: 10px;
    color: #aaa;
    line-height: 1.6;
    flex: 1;
  }
  .doc-footer .stamp-area {
    display: flex;
    gap: 1px;
    flex-shrink: 0;
  }
  .stamp-box {
    width: 64px;
    height: 64px;
    border: 1px solid #ccc;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-between;
    padding: 5px 4px 4px;
  }
  .stamp-box .stamp-label {
    font-size: 8px;
    color: #aaa;
    letter-spacing: 0.06em;
  }
  .stamp-box .stamp-inner {
    flex: 1;
  }

  /* ── Print ── */
  @media print {
    body { background: #fff; }
    .page { padding: 24mm 22mm; max-width: none; }
  }
</style>
</head>
<body>
<div class="page">

  <!-- Header -->
  <div class="doc-header">
    <div class="org">株式会社アークライト　法務部</div>
    <div class="doc-id">No. {{DOC_NO}}</div>
  </div>

  <!-- Title -->
  <div class="doc-title">
    <h1>法務相談 回答書</h1>
    <div class="subtitle">Legal Consultation Response</div>
  </div>

  <!-- Meta -->
  <table class="meta-table">
    <tr>
      <td class="label">回答日</td>
      <td class="value">{{#if RESPONSE_DATE}}{{RESPONSE_DATE}}{{else}}　　　年　　月　　日{{/if}}</td>
    </tr>
    <tr>
      <td class="label">相談部署</td>
      <td class="value">{{CONSULTER_DEPT}}</td>
    </tr>
    <tr>
      <td class="label">相談者</td>
      <td class="value">{{CONSULTER_NAME}}</td>
    </tr>
    <tr>
      <td class="label">件名</td>
      <td class="value">{{SUBJECT}}</td>
    </tr>
    <tr>
      <td class="label">回答担当者</td>
      <td class="value">{{#if RESPONSE_AUTHOR}}{{RESPONSE_AUTHOR}}{{else}}法務部次長　倉持 達也{{/if}}</td>
    </tr>
  </table>

  <!-- Q&A 1 -->
  <div class="qa-block">
    <div class="qa-number">Q &amp; A — 01</div>
    <div class="question-box">
      <div class="box-label">質問</div>
      <div class="content">{{QUESTION_1}}</div>
    </div>
    <div class="answer-box">
      <div class="box-label">回答</div>
      <div class="content">{{ANSWER_1}}</div>
    </div>
  </div>

  {{#if QUESTION_2}}
  <!-- Q&A 2 -->
  <div class="qa-block">
    <div class="qa-number">Q &amp; A — 02</div>
    <div class="question-box">
      <div class="box-label">質問</div>
      <div class="content">{{QUESTION_2}}</div>
    </div>
    <div class="answer-box">
      <div class="box-label">回答</div>
      <div class="content">{{ANSWER_2}}</div>
    </div>
  </div>
  {{/if}}

  {{#if QUESTION_3}}
  <!-- Q&A 3 -->
  <div class="qa-block">
    <div class="qa-number">Q &amp; A — 03</div>
    <div class="question-box">
      <div class="box-label">質問</div>
      <div class="content">{{QUESTION_3}}</div>
    </div>
    <div class="answer-box">
      <div class="box-label">回答</div>
      <div class="content">{{ANSWER_3}}</div>
    </div>
  </div>
  {{/if}}

  <!-- Footer -->
  <div class="doc-footer">
    <div class="note">
      本回答は相談時点の情報に基づくものです。状況の変化により見解が変わる場合があります。<br>
      外部弁護士等の正式な法的意見に代わるものではありません。
    </div>
    <div class="stamp-area">
      <div class="stamp-box"><div class="stamp-label">起案</div><div class="stamp-inner"></div></div>
      <div class="stamp-box"><div class="stamp-label">確認</div><div class="stamp-inner"></div></div>
      <div class="stamp-box"><div class="stamp-label">受領</div><div class="stamp-inner"></div></div>
    </div>
  </div>

</div>
</body>
</html>
