    .revision-notice {
      margin: 0.25em 0 0.9em;
      padding: 0.35em 0.75em;
      border: 0.8pt solid #b8a05a;
      color: #6f5600;
      background: #fffdf2;
      font-size: 8.8pt;
      font-weight: bold;
      text-align: center;
      letter-spacing: 0.03em;
    }
    h1.contract-title {
      text-align: center;
      font-size: 14pt;
      font-weight: bold;
      letter-spacing: 0.18em;
      margin-bottom: 0.9em;
      text-decoration: underline;
      text-underline-offset: 0.22em;
    }
    .preamble {
      font-size: 9.5pt;
      text-indent: 1em;
      margin-bottom: 0.9em;
      line-height: 1.7;
      text-align: justify;
    }
    .tobogaki {
      width: 100%;
      border-collapse: collapse;
      margin-bottom: 1.15em;
      font-size: 9pt;
      line-height: 1.6;
      border-top: 1.5pt solid #1a1a1a;
      border-bottom: 1.5pt solid #1a1a1a;
    }
    .tobogaki th, .tobogaki td {
