<style>
  /* =========================
     Page / Print control
     ========================= */
  @media print {
    body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
    .terms-wrap { font-size: 9.4pt; line-height: 1.55; }
    .terms-title { font-size: 13.5pt; margin: 0 0 1.5mm 0; }
